//go:build e2e

package e2e

import (
	"encoding/json"
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
	"testing"
	"time"
)

// TestP1Failover is the P1 failover-recovery acceptance and the D15 regression
// guard: with a SATURATING bidirectional bulk flow loading both ends, the ACTIVE
// WAN is killed and the bond must reroute egress in BOTH directions within
// P1RecoverySeconds — reliably, with margin, not just on a lucky run — and the flow
// must survive (no WireGuard-session reset).
//
// What is measured, and why THIS way. Recovery is "throughput restored in both
// directions after the active WAN dies". Bidirectional traffic is restored the
// instant BOTH ends have rerouted egress off the dead path; the reroute itself is a
// sub-millisecond Pick()/data-structure update, so the recovery latency in each
// direction is precisely when that end's scheduler logs its "active path change"
// failover. The test reads those two timestamps from the two daemons' logs — a
// sub-millisecond, un-confounded measurement — and takes recovery = max(edge, conc):
//
//   - edge_switch is the FORWARD direction (edge egress → backup);
//   - conc_switch is the REPLY direction (concentrator egress → backup) — the term
//     D15/D16 previously under-budgeted and the one that tailed past 3s under load.
//
// A DATA-plane ping-gap probe was rejected as the timing metric: on the emulated
// single post-failover path it shares one netem queue with the saturating flow and
// is tail-dropped for seconds, which measures congestion, not failover. Instead the
// saturating flow IS the data-plane proof: it spans the kill and must complete with
// positive throughput in both directions, proving the one WireGuard session (hence
// the flow) survived the reroute. (Cross-check: with the load removed a clean
// 20ms-cadence ping gap recovers in ~1.5s, matching the switch latencies — the log
// metric is a faithful proxy for data-plane recovery, just without the confound.)
//
// The load is what made the D15 tail jitter: the concentrator absorbing a saturating
// flood on 4 vCPU starved its probe-loop ticker, delaying the reply-direction detect.
// The T39 fix advances liveness off the receive path too, so the concentrator-side
// switch no longer waits on that starved timer.
//
// Run it MANY times to characterise the tail: `-run TestP1Failover -count=20`. Each
// -count iteration is an independent bring-up + kill + measure; the per-run
// `RECOVERY_MS=` line is parseable for the pass-rate/distribution report.
func TestP1Failover(t *testing.T) {
	bin := buildWanbond(t)
	top := Setup(t)
	edge, conc := setupMultipathTunnelLevel(t, top, bin, DefaultPaths, "info")

	if !top.pingUntil(concInner, 15*time.Second) {
		t.Fatalf("bond never came up\n--- edge ---\n%s\n--- conc ---\n%s", edge.log(), conc.log())
	}

	primary := DefaultPaths[0]   // starlink — the active-backup primary (all egress rides it)
	secondary := DefaultPaths[1] // cellular — the failover backup

	// Let both ends settle so the primary is the established active path on BOTH the
	// edge (egress) and the concentrator (replies) before the kill.
	time.Sleep(1500 * time.Millisecond)

	// A saturating bidirectional bulk flow spans the whole window: it recreates the
	// D15 CPU load AND is the data-plane-survival proof (it must finish with positive
	// throughput both ways). It is uncapped, so both ends' WG crypto runs flat out.
	const loadSecs = 12
	top.startProc(t, "iperf3-server", "nsenter", "-t", strconv.Itoa(top.pid), "-n", "iperf3", "-s", "-1", "-B", concInner)
	time.Sleep(400 * time.Millisecond)
	load := exec.Command("iperf3", "-c", concInner, "-t", strconv.Itoa(loadSecs), "--bidir", "-J")
	loadOut := &lockedBuffer{}
	load.Stdout, load.Stderr = loadOut, loadOut
	if err := load.Start(); err != nil {
		t.Fatalf("start load flow: %v", err)
	}
	// Reap the saturating flow on EVERY exit path, not just load.Wait() on success: a
	// Fatalf before Wait would otherwise leak an uncapped ~70s --bidir iperf3 that keeps
	// saturating the (shared) e2e host and contaminates subsequent/concurrent runs (D21).
	// Kill after a completed Wait is a harmless no-op.
	t.Cleanup(func() {
		if load.Process != nil {
			_ = load.Process.Kill()
		}
	})

	// Let the flow ramp and both ends reach steady state on the primary, then kill the
	// active WAN and stamp the instant.
	time.Sleep(3 * time.Second)
	killAt := time.Now()
	top.Blackhole(primary.name)
	t.Logf("killed active WAN %q at T0", primary.name)

	// Await the bulk flow: a preserved single WG session keeps the connection across
	// the reroute, so a healthy failover exits 0 with positive throughput; a session
	// reset surfaces as a non-zero exit.
	loadErr := load.Wait()
	top.Restore(primary.name)

	// Per-direction failover latency, read from each daemon's scheduler transition.
	edgeSwitch := schedSwitchLatency(edge.log(), killAt)
	concSwitch := schedSwitchLatency(conc.log(), killAt)
	if edgeSwitch < 0 || concSwitch < 0 {
		t.Fatalf("could not measure both failover switches (edge=%s conc=%s) — no scheduler transition logged after the kill\n--- edge ---\n%s\n--- conc ---\n%s",
			latencyStr(edgeSwitch), latencyStr(concSwitch), edge.log(), conc.log())
	}
	// End-to-end bidirectional recovery is governed by the SLOWER of the two ends: both
	// directions carry traffic once both have rerouted.
	recovery := edgeSwitch
	if concSwitch > recovery {
		recovery = concSwitch
	}

	// The single parseable metric line the multi-run harness greps.
	t.Logf("RECOVERY_MS=%d budget_ms=%d failover_budget_ms=%d edge_switch_ms=%d conc_switch_ms=%d",
		recovery.Milliseconds(), int64(P1RecoverySeconds)*1000, PLivenessFailoverBudget.Milliseconds(),
		edgeSwitch.Milliseconds(), concSwitch.Milliseconds())

	// Data-plane survival: the flow that spanned the kill must have carried traffic
	// both ways with no reset.
	fwd, rev := iperfBidirMbps(loadOut.String())
	if loadErr != nil || fwd <= 0 || rev <= 0 {
		t.Errorf("bulk flow did not survive failover (exit err=%v, forward=%.1f Mbit/s, reverse=%.1f Mbit/s) — a WG-session reset?\n%s",
			loadErr, fwd, rev, loadOut.String())
	}

	// Sanity: the backup carries the recovered bond.
	if !top.Reachable(secondary.name, 3) {
		t.Errorf("backup path %q unreachable after failover", secondary.name)
	}

	if recovery >= time.Duration(P1RecoverySeconds)*time.Second {
		t.Errorf("bidirectional recovery %v exceeded P1 budget %ds (edge_switch=%v conc_switch=%v)\n--- edge ---\n%s\n--- conc ---\n%s",
			recovery, P1RecoverySeconds, edgeSwitch, concSwitch, edge.log(), conc.log())
	}
}

// P1 active-backup priority indices: the scheduler's health slice is priority-
// ordered, index 0 the preferred primary and index 1 the failover backup — matching
// the config path order (DefaultPaths[0] primary, DefaultPaths[1] backup). The
// "scheduler active path change" log records the destination index as its "to"
// field, so a to==primaryPathIdx transition is a failback and to==backupPathIdx is a
// failover.
const (
	primaryPathIdx = 0
	backupPathIdx  = 1
)

// TestP1FailoverRepeatedFlap is the SECOND half of the T20 acceptance that
// TestP1Failover (a single kill+restore) does not cover: "repeated flap does not
// wedge the tunnel". It runs ONE long-lived saturating bidirectional bulk flow across
// SEVERAL kill/restore cycles of the ACTIVE WAN and asserts the tunnel recovers every
// cycle — within P1RecoverySeconds, both directions, measured the same sound
// per-direction way as TestP1Failover — and that the single flow survives ALL cycles
// with no WireGuard-session reset.
//
// Non-vacuity guard (the opus T20-r1 finding). A repeated-flap test is only meaningful
// if each cycle genuinely kills the ACTIVE egress path. After a restore the recovered
// primary does not reclaim egress instantly: the scheduler debounces failback with a
// 5s dwell (sched.Config.FailbackAfter), so a blind time.Sleep between cycles could
// kill an already-idle backup and pass trivially. Instead, before every kill this test
// confirms — in BOTH daemons' logs — that egress sits on the primary. For cycles >= 2 it
// waits for a FRESH to-primary "scheduler active path change" (to==0) logged after that
// cycle's restore: that IS the genuine FAILBACK and the anti-wedge proof for the prior
// cycle. Cycle 1 has no prior restore and the lossless primary logs its to-primary
// selection only once at cold-start (before any post-setup instant, and never repeated),
// so it instead reads the CURRENT active path — the most-recent transition's destination
// — and asserts it is the primary. Either way the precondition guarantees the next kill
// hits the active path.
//
// Both daemons run at INFO so those transitions are observable (as in TestP1Failover).
// The per-cycle metric line `FLAP_CYCLE=<n> RECOVERY_MS=<ms>` is grep-able for a
// pass-rate/distribution report over `-run TestP1FailoverRepeatedFlap -count=N`.
func TestP1FailoverRepeatedFlap(t *testing.T) {
	const (
		flapCycles = 3
		// flapFailoverPoll bounds how long we wait to OBSERVE both ends' failover
		// switch after a kill. It is set WELL ABOVE P1RecoverySeconds (not budget+1s)
		// so a heavily-late failover is still OBSERVED and MEASURED — then asserted
		// against the budget with its true magnitude via the per-cycle Errorf below —
		// rather than lost to an unmeasured non-observation Fatalf. The old budget+1s
		// (4s) window was the T20-review measurement gap: a genuine >4s recovery tail
		// fell OUTSIDE it and was reported as "never switched" (an unmeasured Fatalf)
		// instead of "switched late by N ms" (a measured, magnitude-bearing failure).
		flapFailoverPoll = time.Duration(P1RecoverySeconds)*time.Second + 5*time.Second
		// flapFailbackPoll bounds the wait for both ends to fail egress BACK to the
		// primary after a restore: the 5s FailbackAfter dwell + up-detect (3×200ms) +
		// margin for the D15 under-load detection tail. If failback does not complete
		// within this, the tunnel has wedged on the backup.
		flapFailbackPoll = 12 * time.Second
		flapRampBefore   = 2500 * time.Millisecond
	)

	bin := buildWanbond(t)
	top := Setup(t)
	edge, conc := setupMultipathTunnelLevel(t, top, bin, DefaultPaths, "info")

	if !top.pingUntil(concInner, 15*time.Second) {
		t.Fatalf("bond never came up\n--- edge ---\n%s\n--- conc ---\n%s", edge.log(), conc.log())
	}

	primary := DefaultPaths[primaryPathIdx]  // starlink — the active-backup primary
	secondary := DefaultPaths[backupPathIdx] // cellular — the failover backup

	// One saturating bidirectional flow spans EVERY cycle: it recreates the D15 CPU
	// load and is the data-plane-survival proof — it must finish (exit 0) with positive
	// throughput both ways, proving the one WireGuard session (hence the flow) survived
	// all the reroutes. Size its lifetime to the worst-case cycle budget so it is still
	// running throughout the loop no matter how the per-cycle waits resolve.
	loadWindow := flapRampBefore +
		time.Duration(flapCycles)*(flapFailoverPoll+flapFailbackPoll+time.Second) +
		4*time.Second
	loadSecs := int(loadWindow.Seconds()) + 1

	top.startProc(t, "iperf3-server", "nsenter", "-t", strconv.Itoa(top.pid), "-n", "iperf3", "-s", "-1", "-B", concInner)
	time.Sleep(400 * time.Millisecond)
	load := exec.Command("iperf3", "-c", concInner, "-t", strconv.Itoa(loadSecs), "--bidir", "-J")
	loadOut := &lockedBuffer{}
	load.Stdout, load.Stderr = loadOut, loadOut
	if err := load.Start(); err != nil {
		t.Fatalf("start load flow: %v", err)
	}
	// Reap the saturating flow on EVERY exit path, not just the load.Wait() on success:
	// an early Fatalf (a failover non-observation or a failback wedge) before Wait would
	// otherwise leak an uncapped ~70s --bidir iperf3 that keeps saturating the shared e2e
	// host and contaminates subsequent/concurrent runs (D21). Kill after a completed Wait
	// is a harmless no-op.
	t.Cleanup(func() {
		if load.Process != nil {
			_ = load.Process.Kill()
		}
	})

	// Let the flow ramp and both ends reach steady state on the primary before cycle 1.
	time.Sleep(flapRampBefore)

	// sinceRef is the reference instant after which a to-primary transition confirms
	// egress has (re)claimed the primary before the next kill. It is used only for
	// cycles >= 2, where it is the PREVIOUS cycle's restore instant, so each confirmation
	// is that cycle's genuine FAILBACK (a to-primary transition logged strictly after the
	// restore). Cycle 1 does not use it — see the cycle-1 branch below — so its zero
	// value is never read.
	var sinceRef time.Time

	for cycle := 1; cycle <= flapCycles; cycle++ {
		// Precondition (non-vacuity): egress must be on the primary on BOTH ends before
		// we kill it, so the kill genuinely hits the ACTIVE path. This is also the
		// anti-wedge assertion for the prior cycle.
		if cycle == 1 {
			// Cycle 1 cannot demand a FRESH to-primary transition: the cold-start
			// selection to the primary (from:-1→to:0) is logged during bring-up, before
			// any instant we could stamp after setup, and — DefaultPaths being lossless —
			// the primary never re-flaps, so no further to-primary transition is ever
			// logged. A windowed waitBothSwitchTo would therefore time out with a FALSE
			// wedge before any kill. Instead assert the CURRENT active path is the primary
			// by reading the most-recent transition's destination on both ends — robust to
			// the cold-start transition predating any reference instant, and the true
			// non-vacuity precondition (both ends are on the primary now).
			if !waitBothActiveOn(edge, conc, primaryPathIdx, flapFailbackPoll) {
				t.Fatalf("cycle 1: egress not on the primary on both ends within %v at start — cold-start selection never settled on the primary\n--- edge ---\n%s\n--- conc ---\n%s",
					flapFailbackPoll, edge.log(), conc.log())
			}
		} else if _, _, ok := waitBothSwitchTo(edge, conc, sinceRef, primaryPathIdx, flapFailbackPoll); !ok {
			t.Fatalf("cycle %d: egress never (re)claimed the primary on both ends within %v — tunnel wedged on the backup after the prior cycle\n--- edge ---\n%s\n--- conc ---\n%s",
				cycle, flapFailbackPoll, edge.log(), conc.log())
		}

		// Kill the ACTIVE primary and stamp T0 for this cycle.
		killAt := time.Now()
		top.Blackhole(primary.name)

		// Per-direction failover latency, read from each daemon's to-backup transition
		// after this cycle's kill — the same sound, un-confounded measurement as
		// TestP1Failover. End-to-end bidirectional recovery is the SLOWER of the two.
		edgeSwitch, concSwitch, ok := waitBothSwitchTo(edge, conc, killAt, backupPathIdx, flapFailoverPoll)
		if !ok {
			top.Restore(primary.name)
			t.Fatalf("cycle %d: both ends did not fail over to the backup within %v (edge=%s conc=%s %s) — no scheduler transition logged after the kill\n--- edge ---\n%s\n--- conc ---\n%s",
				cycle, flapFailoverPoll, latencyStr(edgeSwitch), latencyStr(concSwitch), readLoadAvg(), edge.log(), conc.log())
		}
		recovery := edgeSwitch
		if concSwitch > recovery {
			recovery = concSwitch
		}
		// Record host load on the metric line: the repeated-flap tail is sensitive to
		// shared-VM CPU contention (4 vCPU, possibly multi-tenant), so every per-cycle
		// measurement carries the load that produced it — that is what lets a genuine
		// product tail be told apart from host-contention noise in the run log (D18).
		t.Logf("FLAP_CYCLE=%d RECOVERY_MS=%d budget_ms=%d edge_switch_ms=%d conc_switch_ms=%d %s",
			cycle, recovery.Milliseconds(), int64(P1RecoverySeconds)*1000,
			edgeSwitch.Milliseconds(), concSwitch.Milliseconds(), readLoadAvg())
		if recovery >= time.Duration(P1RecoverySeconds)*time.Second {
			t.Errorf("cycle %d: bidirectional recovery %v exceeded P1 budget %ds (edge_switch=%v conc_switch=%v %s)",
				cycle, recovery, P1RecoverySeconds, edgeSwitch, concSwitch, readLoadAvg())
		}

		// Restore the primary; the next iteration's precondition wait confirms failback.
		restoreAt := time.Now()
		top.Restore(primary.name)
		sinceRef = restoreAt
	}

	// Final anti-wedge check: after the last restore the bond must return to the
	// primary too (the loop's top-of-cycle check does not cover the last cycle).
	if _, _, ok := waitBothSwitchTo(edge, conc, sinceRef, primaryPathIdx, flapFailbackPoll); !ok {
		t.Errorf("after the final cycle egress never returned to the primary on both ends within %v — tunnel wedged on the backup\n--- edge ---\n%s\n--- conc ---\n%s",
			flapFailbackPoll, edge.log(), conc.log())
	}

	// Data-plane survival across ALL cycles: the one flow that spanned every kill must
	// have completed with traffic both ways and no reset.
	loadErr := load.Wait()
	fwd, rev := iperfBidirMbps(loadOut.String())
	if loadErr != nil || fwd <= 0 || rev <= 0 {
		t.Errorf("bulk flow did not survive %d failover cycles (exit err=%v, forward=%.1f Mbit/s, reverse=%.1f Mbit/s) — a WG-session reset?\n%s",
			flapCycles, loadErr, fwd, rev, loadOut.String())
	}

	// Sanity: the backup path is still reachable (it carried the bond during each cycle).
	if !top.Reachable(secondary.name, 3) {
		t.Errorf("backup path %q unreachable after repeated flap", secondary.name)
	}

	t.Logf("repeated-flap: survived %d kill/restore cycles of the active WAN with one spanning flow (forward=%.1f Mbit/s reverse=%.1f Mbit/s), egress failed back to the primary each cycle",
		flapCycles, fwd, rev)
}

// waitBothSwitchTo polls both daemons' logs until EACH has logged a "scheduler active
// path change" whose destination is toIdx at some instant strictly after `after`, or
// the deadline elapses. It returns the two per-daemon latencies from `after` to that
// transition (or -1 for a daemon that never switched) and whether both were observed.
// It is used both to MEASURE failover (toIdx = backupPathIdx, from the kill instant)
// and to CONFIRM failback (toIdx = primaryPathIdx, from the restore instant) before the
// next kill.
func waitBothSwitchTo(edge, conc *proc, after time.Time, toIdx int, deadline time.Duration) (edgeLat, concLat time.Duration, ok bool) {
	stop := time.Now().Add(deadline)
	for {
		edgeLat = switchToLatency(edge.log(), after, toIdx)
		concLat = switchToLatency(conc.log(), after, toIdx)
		if edgeLat >= 0 && concLat >= 0 {
			return edgeLat, concLat, true
		}
		if time.Now().After(stop) {
			return edgeLat, concLat, false
		}
		time.Sleep(50 * time.Millisecond)
	}
}

// currentActivePathIdx returns the destination index of the MOST-RECENT "scheduler
// active path change" transition in a daemon's log, or -1 if none has been logged. It
// is NOT windowed by an instant: it reports the scheduler's CURRENT active path
// regardless of when that transition was logged. Cycle 1's precondition uses it to
// confirm the cold-start selection put egress on the primary WITHOUT demanding a fresh
// post-setup transition — the lossless primary logs its to-primary selection only once
// at bring-up and never re-flaps, so no such fresh transition ever exists.
func currentActivePathIdx(logText string) int {
	idx := -1
	var latest time.Time
	for _, line := range strings.Split(logText, "\n") {
		if !strings.Contains(line, "scheduler active path change") {
			continue
		}
		var rec struct {
			Time time.Time `json:"time"`
			To   int       `json:"to"`
		}
		if err := json.Unmarshal([]byte(line), &rec); err != nil {
			continue
		}
		if idx < 0 || rec.Time.After(latest) {
			latest = rec.Time
			idx = rec.To
		}
	}
	return idx
}

// waitBothActiveOn polls both daemons' logs until EACH reports its CURRENT active path
// (the most-recent transition's destination) is toIdx, or the deadline elapses. Unlike
// waitBothSwitchTo it asserts the PRESENT active path rather than a fresh transition
// after some instant, so it confirms cycle 1's cold-start selection without requiring a
// to-primary transition logged after a reference time.
func waitBothActiveOn(edge, conc *proc, toIdx int, deadline time.Duration) bool {
	stop := time.Now().Add(deadline)
	for {
		if currentActivePathIdx(edge.log()) == toIdx && currentActivePathIdx(conc.log()) == toIdx {
			return true
		}
		if time.Now().After(stop) {
			return false
		}
		time.Sleep(50 * time.Millisecond)
	}
}

// switchToLatency returns the delay from `after` to the EARLIEST "scheduler active
// path change" transition to destination index toIdx logged strictly after `after`, or
// -1 if none. It is schedSwitchLatency refined by the transition's "to" field, so a
// failover (to the backup) and a failback (to the primary) can be told apart in a log
// that accumulates both across repeated cycles.
func switchToLatency(logText string, after time.Time, toIdx int) time.Duration {
	best := time.Duration(-1)
	for _, line := range strings.Split(logText, "\n") {
		if !strings.Contains(line, "scheduler active path change") {
			continue
		}
		var rec struct {
			Time time.Time `json:"time"`
			To   int       `json:"to"`
		}
		if err := json.Unmarshal([]byte(line), &rec); err != nil {
			continue
		}
		if rec.To != toIdx || !rec.Time.After(after) {
			continue
		}
		d := rec.Time.Sub(after)
		if best < 0 || d < best {
			best = d
		}
	}
	return best
}

// schedSwitchLatency returns the delay from killAt to the first "scheduler active
// path change" transition in a daemon's JSON log after the kill, or -1 if none is
// found (the daemon log is slog JSON: {"time":...,"msg":"scheduler active path
// change",...}). It is the per-direction failover-recovery latency: the reroute is a
// sub-ms update, so the transition timestamp is when that end's egress moves to the
// surviving path.
func schedSwitchLatency(logText string, killAt time.Time) time.Duration {
	best := time.Duration(-1)
	for _, line := range strings.Split(logText, "\n") {
		if !strings.Contains(line, "scheduler active path change") {
			continue
		}
		var rec struct {
			Time time.Time `json:"time"`
		}
		if err := json.Unmarshal([]byte(line), &rec); err != nil {
			continue
		}
		if rec.Time.Before(killAt) {
			continue // the initial cold-start selection, not the failover
		}
		d := rec.Time.Sub(killAt)
		if best < 0 || d < best {
			best = d
		}
	}
	return best
}

// iperfBidirMbps parses an iperf3 --bidir -J report, returning the forward
// (client→server, sum_sent) and reverse (server→client, sum_received) throughput in
// Mbit/s. Zero for either direction (or an unparseable report) signals the flow did
// not carry traffic that way.
func iperfBidirMbps(out string) (forward, reverse float64) {
	var r struct {
		End struct {
			SumSent struct {
				BitsPerSecond float64 `json:"bits_per_second"`
			} `json:"sum_sent"`
			SumReceived struct {
				BitsPerSecond float64 `json:"bits_per_second"`
			} `json:"sum_received"`
		} `json:"end"`
	}
	if err := json.Unmarshal([]byte(out), &r); err != nil {
		return 0, 0
	}
	return r.End.SumSent.BitsPerSecond / 1e6, r.End.SumReceived.BitsPerSecond / 1e6
}

// latencyStr renders a measured latency, or "n/a" for a missing (-1) measurement.
func latencyStr(d time.Duration) string {
	if d < 0 {
		return "n/a"
	}
	return fmt.Sprintf("%d", d.Milliseconds())
}

// readLoadAvg returns the host's 1/5/15-minute load averages as a compact
// "load=1min,5min,15min" token (or "load=?" if /proc/loadavg is unreadable). The
// repeated-flap failover tail is sensitive to shared-VM CPU contention — the e2e host
// runs on 4 vCPU and may be multi-tenant — so every per-cycle metric line and every
// budget-exceeded/non-observation failure stamps the load that accompanied it. That
// is the robustness the D18 investigation added: a future over-budget cycle is
// self-classifying from the log alone (a high load average points at host contention;
// a low one at a genuine product regression) instead of needing an out-of-band host
// snapshot that no longer exists by the time the failure is read.
func readLoadAvg() string {
	b, err := os.ReadFile("/proc/loadavg")
	if err != nil {
		return "load=?"
	}
	f := strings.Fields(string(b))
	if len(f) < 3 {
		return "load=?"
	}
	return fmt.Sprintf("load=%s,%s,%s", f[0], f[1], f[2])
}

//go:build e2e

package e2e

import (
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
	"testing"
	"time"
)

// pathSpec describes one emulated WAN uplink between the edge and concentrator
// namespaces: a veth pair carrying a /24, with netem delay+jitter on the edge
// egress. The bandwidth cap (rateMbit) and controlled loss (lossPct) are
// OPTIONAL config-time impairments: both default to zero, so the DefaultPaths
// topology stays uncapped and lossless and every existing P0/P1 e2e test runs
// unchanged. A non-zero rateMbit makes the LINK — not the single-core userspace
// WG crypto — the bottleneck ONLY when rateMbit sits below the EXECUTING host's
// measured in-fixture tunnel ceiling. That ceiling is CPU/PPS-bound (both daemons
// plus the load generator share the host's cores), a lower bound that scales with
// core count, NOT a link-throughput spec: ~12–46 Mbit/s single-flow on a 1-vCPU
// aarch64 host (docs/p0-findings.md:216-225), ~13 Mbit/s single-path (up to
// ~47–87 Mbit/s FEC single-flow) on a 4-vCPU amd64 host. Sizing rule: cap < ceiling
// for single-path, 2×cap < ceiling for aggregation. Below the ceiling
// a standing queue can form for bufferbloat/pacing (T21/T23) work; a non-zero
// lossPct injects uniform egress loss at Setup time for FEC-recovery (T25/T29)
// work.
type pathSpec struct {
	name     string
	edgeIP   string
	concIP   string
	edgeVeth string // <=15 chars
	concVeth string
	delayMs  int
	jitterMs int
	rateMbit int     // optional per-path bandwidth cap (netem rate); 0 = uncapped
	lossPct  float64 // optional config-time uniform egress loss (netem loss); 0 = lossless

	// deferEdgeAddr, when true, makes Setup create and bring up the edge veth WITHOUT
	// assigning edgeIP to it: the interface exists (so tc/netem still applies and the
	// link is up) but the configured source_addr is not yet owned by any interface —
	// the well-formed-but-not-yet-assignable condition T51's tolerant Open() defers and
	// T55's background reconcile later promotes (T60). AddEdgeAddr adds the withheld
	// address later. Zero value (false) is the default for every existing path, so
	// Setup's behaviour for DefaultPaths and every other caller is unchanged.
	deferEdgeAddr bool
}

// DefaultPaths are the two emulated links: Starlink-like (low latency, jittery)
// and 5G-like (higher latency, stable).
var DefaultPaths = []pathSpec{
	{name: "starlink", edgeIP: "10.100.1.1", concIP: "10.100.1.2", edgeVeth: "wbAe", concVeth: "wbAc", delayMs: 45, jitterMs: 10},
	{name: "cellular", edgeIP: "10.100.2.1", concIP: "10.100.2.2", edgeVeth: "wbBe", concVeth: "wbBc", delayMs: 64, jitterMs: 0},
}

// Topology is a two-namespace netns/netem fixture. The edge side is the current
// (re-exec'd) network namespace; the concentrator side is a child process's
// network namespace, addressed by PID so no writable /run/netns is required.
type Topology struct {
	t      *testing.T
	holder *exec.Cmd
	pid    int
	paths  []pathSpec
}

// Setup builds the two-path topology from DefaultPaths (uncapped, lossless). It
// requires CAP_NET_ADMIN, which the e2e TestMain provides via an unprivileged
// user+net namespace (`unshare -Urmn`).
func Setup(t *testing.T) *Topology {
	return SetupWithPaths(t, DefaultPaths)
}

// SetupWithPaths builds the topology from an explicit path set, allowing a test
// to opt into the optional per-path bandwidth cap (rateMbit) and/or config-time
// loss (lossPct). DefaultPaths leaves both zero, so Setup is unchanged.
func SetupWithPaths(t *testing.T, paths []pathSpec) *Topology {
	t.Helper()
	top := &Topology{t: t, paths: paths}

	// Hold the concentrator network namespace open with a sleeping child.
	top.holder = exec.Command("unshare", "-n", "sleep", "600")
	if err := top.holder.Start(); err != nil {
		t.Fatalf("start concentrator netns holder: %v", err)
	}
	top.pid = top.holder.Process.Pid
	top.waitForNetns()

	pid := strconv.Itoa(top.pid)
	top.run("ip", "link", "set", "lo", "up")
	top.nsenter("ip", "link", "set", "lo", "up")
	// Pin net.ipv4.ip_nonlocal_bind=0 in the edge (test-process) network namespace, so
	// a path whose source_addr is NOT assigned to any interface deterministically fails
	// to bind (EADDRNOTAVAIL) instead of succeeding. That non-local-bind FAILURE is the
	// premise the tolerant-startup tests (T60) rest on: a not-yet-assignable source_addr
	// must DEFER (T51) and a config where NO path can bind must fail Open. A host that
	// leaves the sysctl at 1 (or runs permissively) lets a non-local bind SUCCEED, which
	// silently voids both premises (observed nondeterministic on a real host: a deferred
	// path binding instead of deferring, or a zero-bindable daemon coming up). A fresh
	// netns SHOULD default to 0, but pin it explicitly rather than trust the default.
	// This affects ONLY non-local binds, so every other e2e test — which binds real,
	// assigned addresses — is byte-for-byte unaffected. The concentrator netns needs no
	// pin: every concentrator source_addr (concIP) IS assigned there (deferEdgeAddr only
	// withholds the EDGE address), so the concentrator never binds a non-local address.
	disableNonlocalBind(top.t)
	for _, p := range top.paths {
		// Idempotent pre-delete: the veth names are FIXED per path, so a prior subtest's
		// teardown racing the kernel's async netns/veth reap can leave the edge veth behind,
		// making `ip link add` fail with EEXIST ("File exists"). Deleting the pair first
		// (ignore-if-absent) makes Setup robust to reused fixed names across sequential
		// subtests. Deleting the edge end removes its peer too.
		_ = top.tryRun("ip", "link", "del", p.edgeVeth)
		top.run("ip", "link", "add", p.edgeVeth, "type", "veth", "peer", "name", p.concVeth)
		top.run("ip", "link", "set", p.concVeth, "netns", pid)
		if !p.deferEdgeAddr {
			top.run("ip", "addr", "add", p.edgeIP+"/24", "dev", p.edgeVeth)
		}
		top.run("ip", "link", "set", p.edgeVeth, "up")
		top.nsenter("ip", "addr", "add", p.concIP+"/24", "dev", p.concVeth)
		top.nsenter("ip", "link", "set", p.concVeth, "up")
		qargs := append([]string{"qdisc", "add", "dev", p.edgeVeth, "root", "netem"}, top.netemArgs(p)...)
		top.run("tc", qargs...)
	}
	t.Cleanup(top.Teardown)
	return top
}

// waitForNetns blocks until the holder's network namespace is observable.
func (top *Topology) waitForNetns() {
	path := fmt.Sprintf("/proc/%d/ns/net", top.pid)
	for i := 0; i < 100; i++ {
		if _, err := os.Stat(path); err == nil {
			return
		}
		time.Sleep(10 * time.Millisecond)
	}
	top.t.Fatalf("concentrator netns %s never appeared", path)
}

// netemArgs builds the netem parameter list for a path's baseline impairment
// profile: delay/jitter, then its configured loss (lossPct) and bandwidth cap
// (rateMbit) if set. For a DefaultPaths entry (both zero) this reduces to the
// prior delay/jitter-only output, so existing qdisc setup is byte-identical.
func (top *Topology) netemArgs(p pathSpec) []string {
	return top.netemArgsWithLoss(p, p.lossPct)
}

// netemArgsWithLoss is netemArgs with the loss percentage overridden — used by
// InjectLoss to set runtime loss while preserving delay/jitter and any rate cap.
// netem accepts the options in delay/loss/rate order.
func (top *Topology) netemArgsWithLoss(p pathSpec, lossPct float64) []string {
	args := []string{"delay", fmt.Sprintf("%dms", p.delayMs)}
	if p.jitterMs > 0 {
		args = append(args, fmt.Sprintf("%dms", p.jitterMs))
	}
	if lossPct > 0 {
		args = append(args, "loss", fmt.Sprintf("%g%%", lossPct))
	}
	if p.rateMbit > 0 {
		args = append(args, "rate", fmt.Sprintf("%dmbit", p.rateMbit))
	}
	return args
}

// path looks up a path by name, failing the test if absent.
func (top *Topology) path(name string) pathSpec {
	for _, p := range top.paths {
		if p.name == name {
			return p
		}
	}
	top.t.Fatalf("unknown path %q", name)
	return pathSpec{}
}

// RTT pings the concentrator end of the named path from the edge and returns the
// average round-trip time in milliseconds.
func (top *Topology) RTT(name string, count int) float64 {
	p := top.path(name)
	out := top.runOut("ping", "-c", strconv.Itoa(count), "-i", "0.2", "-W", "1", p.concIP)
	// rtt min/avg/max/mdev = 37.264/48.520/82.043/19.354 ms
	idx := strings.Index(out, "min/avg/max")
	if idx < 0 {
		top.t.Fatalf("path %q: no rtt line in ping output:\n%s", name, out)
	}
	eq := strings.Index(out[idx:], "=")
	fields := strings.Fields(out[idx+eq+1:])
	nums := strings.Split(fields[0], "/")
	avg, err := strconv.ParseFloat(nums[1], 64)
	if err != nil {
		top.t.Fatalf("path %q: parse avg rtt %q: %v", name, nums[1], err)
	}
	return avg
}

// Reachable reports whether the concentrator end of the named path answers pings.
func (top *Topology) Reachable(name string, count int) bool {
	p := top.path(name)
	return top.tryRun("ping", "-c", strconv.Itoa(count), "-i", "0.2", "-W", "1", p.concIP) == nil
}

// InjectLoss sets uniform egress loss (percent) on the named path at runtime,
// preserving its delay/jitter profile and any configured bandwidth cap.
func (top *Topology) InjectLoss(name string, pct float64) {
	p := top.path(name)
	args := append([]string{"qdisc", "change", "dev", p.edgeVeth, "root", "netem"}, top.netemArgsWithLoss(p, pct)...)
	top.run("tc", args...)
}

// ClearLoss restores the named path to its configured baseline impairment
// (delay/jitter, plus any config-time loss and bandwidth cap). For a DefaultPaths
// entry that is delay/jitter only.
func (top *Topology) ClearLoss(name string) {
	p := top.path(name)
	args := append([]string{"qdisc", "change", "dev", p.edgeVeth, "root", "netem"}, top.netemArgs(p)...)
	top.run("tc", args...)
}

// Blackhole brings the named path's edge link down, simulating a WAN death (used
// by the P1 failover test).
func (top *Topology) Blackhole(name string) {
	p := top.path(name)
	top.run("ip", "link", "set", p.edgeVeth, "down")
}

// Restore brings the named path's edge link back up.
func (top *Topology) Restore(name string) {
	p := top.path(name)
	top.run("ip", "link", "set", p.edgeVeth, "up")
}

// BlockEgress drops ALL outbound traffic on the named path's edge veth via a tc
// clsact egress filter (matchall + drop), while leaving the veth up and inbound
// traffic untouched — a one-way egress failure (e.g. a dead uplink amplifier), as
// opposed to Blackhole's bidirectional link-down. It is used by T104 to prove
// liveness is genuinely bidirectional: with only egress dead the peer's own probes
// still ARRIVE at this path (an operator naively trusting "receiving traffic" as
// health would stay wrongly up), but this path's OWN probe/echo round trip cannot
// complete, so it must go DOWN. clsact attaches its own ingress/egress hooks
// independent of whatever root qdisc is set, so it coexists with the path's netem
// root qdisc (delay/jitter/loss) without disturbing it.
func (top *Topology) BlockEgress(name string) {
	p := top.path(name)
	top.run("tc", "qdisc", "add", "dev", p.edgeVeth, "clsact")
	top.run("tc", "filter", "add", "dev", p.edgeVeth, "egress", "protocol", "all", "matchall", "action", "drop")
}

// UnblockEgress removes a BlockEgress filter, restoring the named path's egress.
// Idempotent — deleting an already-absent clsact qdisc is tolerated — so a test may
// call it both explicitly and via t.Cleanup without failing on the second call.
func (top *Topology) UnblockEgress(name string) {
	p := top.path(name)
	_ = top.tryRun("tc", "qdisc", "del", "dev", p.edgeVeth, "clsact")
}

// Readdress replaces the edge-side address of the named path, simulating an edge
// public-IP change (used by the P1 roaming test). newEdgeIP must be a bare IPv4
// address in the path's /24.
func (top *Topology) Readdress(name, newEdgeIP string) {
	p := top.path(name)
	top.run("ip", "addr", "flush", "dev", p.edgeVeth)
	top.run("ip", "addr", "add", newEdgeIP+"/24", "dev", p.edgeVeth)
	top.run("ip", "link", "set", p.edgeVeth, "up")
}

// AddEdgeAddr adds the named path's configured edge-side address to its (already up)
// edge veth, WITHOUT flushing any existing address first (T60). It is the companion
// to a path built with deferEdgeAddr: that path's interface starts addressless, so
// this simulates the address becoming assignable after boot (e.g. a 5G modem's DHCP
// lease completing) for the T55 background reconciler to observe. Unlike Readdress —
// which flushes THEN re-adds, for the T16 re-roam case where an address is replaced —
// this only ADDS, because here there is nothing to flush.
func (top *Topology) AddEdgeAddr(name string) {
	p := top.path(name)
	top.run("ip", "addr", "add", p.edgeIP+"/24", "dev", p.edgeVeth)
}

// nonlocalBindProc is the per-netns sysctl controlling whether a socket may bind a
// source address that is NOT assigned to any local interface. 0 (the value the
// tolerant-startup tests pin) makes such a bind fail EADDRNOTAVAIL; 1 lets it
// succeed. It is a plain proc file, so it is written/read directly rather than via
// the `sysctl` binary (one fewer external dependency).
const nonlocalBindProc = "/proc/sys/net/ipv4/ip_nonlocal_bind"

// disableNonlocalBind pins ip_nonlocal_bind=0 in the CURRENT (edge/test) network
// namespace and asserts the value took, failing the test loudly if it cannot be set.
// A hard failure here — rather than proceeding — is deliberate: the tolerant-startup
// premise (a non-local bind must fail) is silently voided if the sysctl stays at 1,
// so an un-pinnable environment must surface as a test failure, never a false pass.
// os.WriteFile targets THIS process's netns, which is the edge/test namespace (the
// TestMain re-exec unshared it), exactly where the not-yet-assignable source_addr
// binds live. Writing a per-netns net sysctl needs the same privilege the fixture's
// veth/netem setup already requires, so anywhere the netns tier runs, this succeeds.
func disableNonlocalBind(t *testing.T) {
	t.Helper()
	if err := os.WriteFile(nonlocalBindProc, []byte("0\n"), 0o644); err != nil {
		t.Fatalf("pin %s=0: %v (the tolerant-startup tests need a non-local bind to fail EADDRNOTAVAIL; without this a permissive host silently voids the premise)", nonlocalBindProc, err)
	}
	got, err := os.ReadFile(nonlocalBindProc)
	if err != nil {
		t.Fatalf("read back %s: %v", nonlocalBindProc, err)
	}
	if v := strings.TrimSpace(string(got)); v != "0" {
		t.Fatalf("%s = %q after pin, want 0 — a non-local bind would still succeed and void the zero-bindable/deferred premise", nonlocalBindProc, v)
	}
}

// bringLoopbackUp brings the loopback interface UP in the CURRENT (edge/test)
// network namespace. It is a second, INDEPENDENT precondition for a non-local bind
// to fail EADDRNOTAVAIL: on this kernel the rejection fires only when at least one
// interface is UP — empirically, with lo DOWN a bind to a non-local address SUCCEEDS
// even at ip_nonlocal_bind=0 (kernel probe: lo-up+pin0 -> EADDRNOTAVAIL; lo-down+pin0
// -> BIND_OK; lo-up+pin1 -> BIND_OK). So the zero-bindable premise needs BOTH lo UP
// and the sysctl pinned to 0. SetupWithPaths already brings lo up for topology tests
// (line above), which is why the zero-bindable subtest passed only when it happened to
// run AFTER one; building no topology itself, it must bring lo up explicitly to hold
// regardless of subtest execution order. Idempotent (setting an already-up lo up is a
// no-op). Runs in this process's netns (the TestMain re-exec unshared it), like run().
func bringLoopbackUp(t *testing.T) {
	t.Helper()
	if out, err := exec.Command("ip", "link", "set", "lo", "up").CombinedOutput(); err != nil {
		t.Fatalf("bring lo up in the test netns: %v\n%s", err, out)
	}
}

// QdiscShow returns `tc qdisc show` for the named path (for assertions/debug).
func (top *Topology) QdiscShow(name string) string {
	p := top.path(name)
	return top.runOut("tc", "qdisc", "show", "dev", p.edgeVeth)
}

// LinkExists reports whether the edge-side veth of the named path still exists.
func (top *Topology) LinkExists(name string) bool {
	p := top.path(name)
	return top.tryRun("ip", "link", "show", p.edgeVeth) == nil
}

// Teardown removes the topology. Killing the holder drops the concentrator netns
// (and its veth ends); the edge-side veths are deleted explicitly. Idempotent.
func (top *Topology) Teardown() {
	for _, p := range top.paths {
		_ = top.tryRun("ip", "link", "del", p.edgeVeth)
	}
	if top.holder != nil && top.holder.Process != nil {
		_ = top.holder.Process.Kill()
		_, _ = top.holder.Process.Wait()
		top.holder = nil
	}
}

func (top *Topology) run(name string, args ...string) {
	top.t.Helper()
	if out, err := exec.Command(name, args...).CombinedOutput(); err != nil {
		top.t.Fatalf("%s %s: %v\n%s", name, strings.Join(args, " "), err, out)
	}
}

func (top *Topology) tryRun(name string, args ...string) error {
	return exec.Command(name, args...).Run()
}

func (top *Topology) runOut(name string, args ...string) string {
	top.t.Helper()
	out, err := exec.Command(name, args...).CombinedOutput()
	if err != nil {
		top.t.Fatalf("%s %s: %v\n%s", name, strings.Join(args, " "), err, out)
	}
	return string(out)
}

// iperfListenTimeout bounds waitIperfListen: how long to wait for the one-shot
// iperf3 server to reach the LISTEN state before failing the test.
const iperfListenTimeout = 5 * time.Second

// waitIperfListen polls, inside the concentrator network namespace, for a TCP
// socket in the LISTEN state on the given port, and returns once it appears (or
// fails the test at iperfListenTimeout). It reads kernel socket state via
// `ss -ltn` and NEVER connects: the iperf3 servers here run one-shot (`-s -1`),
// so a probe-connect would consume the server's single accept and break the real
// client. It replaces the prior fixed sleeps at the iperf3Mbps and rttUnderLoad
// call sites, which raced a slow bind under load into 'connection refused' (D3).
func (top *Topology) waitIperfListen(t *testing.T, port int) {
	t.Helper()
	suffix := fmt.Sprintf(":%d", port)
	deadline := time.Now().Add(iperfListenTimeout)
	for time.Now().Before(deadline) {
		// ss -ltn columns: State Recv-Q Send-Q Local-Address:Port Peer-Address:Port.
		out, err := exec.Command("nsenter", "-t", strconv.Itoa(top.pid), "-n", "ss", "-ltn").CombinedOutput()
		if err == nil {
			for _, line := range strings.Split(string(out), "\n") {
				fields := strings.Fields(line)
				if len(fields) >= 4 && strings.HasSuffix(fields[3], suffix) {
					return
				}
			}
		}
		time.Sleep(20 * time.Millisecond)
	}
	t.Fatalf("iperf3 server never reached LISTEN on port %d within %s", port, iperfListenTimeout)
}

// nsenter runs a command inside the concentrator network namespace.
func (top *Topology) nsenter(args ...string) {
	top.t.Helper()
	full := append([]string{"-t", strconv.Itoa(top.pid), "-n"}, args...)
	top.run("nsenter", full...)
}

//go:build e2e

package e2e

import (
	"context"
	"errors"
	"fmt"
	"net/http"
	"os/exec"
	"path/filepath"
	"strconv"
	"strings"
	"testing"
	"time"

	"github.com/7mind/wanbond/internal/bind"
	"github.com/7mind/wanbond/internal/metrics"
	"github.com/7mind/wanbond/internal/telemetry"
)

// T60 is the netns e2e for the W1 startup-resilience feature END TO END: T51's
// tolerant Open() (defer a well-formed but not-yet-assignable source_addr instead of
// refusing the whole bond) composed with T55's background reconcile (promote a
// deferred path to live once its address appears), plus the two fast-fail edges
// (zero bindable paths; a malformed source_addr) that tolerance must NOT paper over.

const (
	// t60MetricsListen is the edge's /metrics endpoint for this file's tests, on a
	// port none of the other e2e files use (see test/e2e/p2/p3/p4/pacing for 9095-97).
	t60MetricsListen = "127.0.0.1:9098"
	t60MetricsURL    = "http://" + t60MetricsListen + "/metrics"

	// t60UnassignableSrcA/B mirror internal/bind/tolerant_bind_test.go's
	// unassignableSource: 192.0.2.0/24 is TEST-NET-1 (RFC 5737), reserved for
	// documentation and guaranteed never configured on a real interface, so a bind
	// against it deterministically fails EADDRNOTAVAIL without any netns fixture.
	t60UnassignableSrcA = "192.0.2.1"
	t60UnassignableSrcB = "192.0.2.2"
)

// t60DeferredPath is the THIRD emulated uplink (distinct veth names from
// DefaultPaths' starlink/cellular): its edge address is deliberately withheld at
// Setup (deferEdgeAddr), so wbCe exists and is up but 10.100.3.1 is not yet owned by
// any interface — the well-formed-but-not-yet-assignable condition T51 defers.
// top.AddEdgeAddr("modem5g") later adds it, simulating the address appearing.
var t60DeferredPath = pathSpec{
	name: "modem5g", edgeIP: "10.100.3.1", concIP: "10.100.3.2",
	edgeVeth: "wbCe", concVeth: "wbCc", delayMs: 20,
	deferEdgeAddr: true,
}

// t60PromoteTimeout bounds how long the T55 background reconcile may take to bind,
// promote, and bring the deferred path's liveness to Up after its address appears:
// one worst-case reconcile tick (bind.DefaultReconcileInterval, the poll cadence)
// plus the liveness up-transition (DefaultUpSuccesses consecutive probe echoes at
// DefaultProbeInterval), plus harness slack for scheduling jitter under the fixture's
// shared CPU — mirroring the analytical-bound style of thresholds.go's
// PLivenessFailoverBudget/PLivenessDetectBudget.
const t60PromoteTimeout = bind.DefaultReconcileInterval +
	time.Duration(telemetry.DefaultUpSuccesses)*telemetry.DefaultProbeInterval +
	3*time.Second

// TestTolerantStartupDeferredPathPromotes is the T60 acceptance: bring the bond up
// with TWO paths where one (modem5g) names a well-formed source_addr that is not yet
// assignable on any interface. The bond must come up on the survivor (starlink) —
// handshake + traffic — while modem5g is present in config but excluded from the
// live path set (not fatal). Adding the missing address must then let T55's
// background reconcile bind, promote, and carry traffic on modem5g.
func TestTolerantStartupDeferredPathPromotes(t *testing.T) {
	bin := buildWanbond(t)
	survivor := DefaultPaths[0] // starlink
	paths := []pathSpec{survivor, t60DeferredPath}
	top := SetupWithPaths(t, paths)
	edge, conc := setupT60Tunnel(t, top, bin, paths, t60MetricsListen)

	// (1) The bond comes up on the survivor alone: modem5g's source_addr is not yet
	// assignable, so its bind deferred rather than failing the whole Open (T51).
	if !top.pingUntil(concInner, 15*time.Second) {
		t.Fatalf("bond never came up on the survivor path %q while %q was deferred\n--- edge ---\n%s\n--- conc ---\n%s",
			survivor.name, t60DeferredPath.name, edge.log(), conc.log())
	}
	mbps := top.iperf3Mbps(t, concInner, 3)
	if mbps <= 0 {
		t.Fatalf("survivor path %q carried non-positive throughput %.2f Mbit/s", survivor.name, mbps)
	}

	// The deferred path is PRESENT in config but excluded from the live/served set:
	// bind.Multipath.PathSnapshots() — what the /metrics endpoint scrapes — reports
	// only BOUND paths (m.paths), so a still-deferred path's wanbond_path_up series is
	// simply ABSENT, not zero. This operationalizes "present-but-down, not fatal":
	// the daemon is running, the survivor is up, and the deferred path has no live
	// series until T55 promotes it.
	before := scrapeMetrics(t, t60MetricsURL)
	if _, ok := before.PathValue(metrics.MetricUp, t60DeferredPath.name); ok {
		t.Fatalf("deferred path %q already has a wanbond_path_up series before its address was added; it should be absent (not yet promoted)", t60DeferredPath.name)
	}
	if v, ok := before.PathValue(metrics.MetricUp, survivor.name); !ok || v != 1 {
		t.Fatalf("survivor path %q wanbond_path_up = %v (present=%v), want 1", survivor.name, v, ok)
	}
	t.Logf("pre-promote: survivor %q up (iperf3=%.1f Mbit/s), deferred %q absent from live metrics as expected", survivor.name, mbps, t60DeferredPath.name)

	// (2) The missing address appears — e.g. the 5G modem's DHCP lease completes.
	top.AddEdgeAddr(t60DeferredPath.name)

	// T55's background reconcile must bind, promote, and bring the path's liveness to
	// Up within the analytical budget above.
	waitPathUp(t, t60MetricsURL, t60DeferredPath.name, 1, t60PromoteTimeout)

	// Prove the PROMOTED path itself carries traffic (not merely that the bond
	// survives): blackhole the survivor so only the reconciled path can forward. The
	// active-backup scheduler's Pick can only land here once modem5g is genuinely
	// admitted and healthy.
	top.Blackhole(survivor.name)
	if !top.pingUntil(concInner, time.Duration(P1RecoverySeconds)*time.Second+2*time.Second) {
		t.Fatalf("tunnel did not recover on the promoted path %q once the survivor %q was blackholed\n--- edge ---\n%s\n--- conc ---\n%s",
			t60DeferredPath.name, survivor.name, edge.log(), conc.log())
	}
	promotedMbps := top.iperf3Mbps(t, concInner, 3)
	if promotedMbps <= 0 {
		t.Fatalf("promoted path %q carried non-positive throughput %.2f Mbit/s", t60DeferredPath.name, promotedMbps)
	}
	top.Restore(survivor.name)

	t.Logf("T60: survivor %q up first (iperf3=%.1f Mbit/s) while %q was deferred; after its address was added, T55 promoted it and it alone carried iperf3=%.1f Mbit/s",
		survivor.name, mbps, t60DeferredPath.name, promotedMbps)
}

// TestTolerantStartupFastFailModes asserts the two edges tolerance must NOT paper
// over: zero bindable paths (every source_addr unassignable) is a FATAL Open, and a
// malformed source_addr is rejected at config LOAD, before the daemon ever attempts a
// bind. Both run in the test-process network namespace (the TestMain re-exec unshared
// it); neither needs the veth topology, since both source addresses are TEST-NET-1
// (RFC 5737, never assignable on any real interface) or simply invalid syntax.
func TestTolerantStartupFastFailModes(t *testing.T) {
	bin := buildWanbond(t)

	t.Run("zero_bindable_paths_is_fatal", func(t *testing.T) {
		// Determinism (hardware-robustness fix): the zero-bindable premise is that BOTH
		// source_addrs fail to bind, i.e. a bind to a non-local address returns
		// EADDRNOTAVAIL. On this kernel that rejection needs TWO conditions, BOTH pinned
		// here so the premise holds regardless of host default or subtest order:
		//   (1) at least one interface UP — with lo DOWN a non-local bind SUCCEEDS even at
		//       ip_nonlocal_bind=0 (empirical kernel probe on llm-ubuntu-0); this subtest
		//       builds no topology, so it must bring lo up itself (bringLoopbackUp);
		//   (2) net.ipv4.ip_nonlocal_bind=0 — a host at 1 lets a non-local bind succeed
		//       (disableNonlocalBind, which fails loudly if it cannot pin the value).
		// Together they make "no configured path can bind -> fatal Open" deterministic.
		// The original fix pinned only (2) and mis-identified the variable, so the daemon
		// came up (both TEST-NET-1 addresses bound) and the test hung — the false-negative
		// observed on llm-ubuntu-0 when this subtest ran alone (lo down).
		bringLoopbackUp(t)
		disableNonlocalBind(t)

		cfg := writeT60EdgeConfig(t, fmt.Sprintf(`[[paths]]
name = "a"
source_addr = "%s"

[[paths]]
name = "b"
source_addr = "%s"
`, t60UnassignableSrcA, t60UnassignableSrcB))

		code, out := runWanbondOnce(t, bin, cfg, 10*time.Second)
		if code == 0 {
			t.Fatalf("wanbond exited 0 with zero bindable paths (both %s/%s are TEST-NET-1, never assignable); want a fatal non-zero exit\n%s",
				t60UnassignableSrcA, t60UnassignableSrcB, out)
		}
		if !strings.Contains(out, "wanbond starting") {
			t.Fatalf("expected the daemon to log startup before failing at Open — that is what distinguishes this fatal-Open case from a config-load error; output:\n%s", out)
		}
		if !strings.Contains(out, "no configured path could bind") {
			t.Fatalf("expected the bind's zero-bindable fatal error message; output:\n%s", out)
		}
		t.Logf("zero-bindable-paths: wanbond exited %d as expected:\n%s", code, out)
	})

	t.Run("malformed_source_addr_is_config_load_error", func(t *testing.T) {
		cfg := writeT60EdgeConfig(t, `[[paths]]
name = "a"
source_addr = "not-an-ip-address"
`)

		code, out := runWanbondOnce(t, bin, cfg, 10*time.Second)
		if code == 0 {
			t.Fatalf("wanbond exited 0 with a malformed source_addr; want a config-load error\n%s", out)
		}
		if strings.Contains(out, "wanbond starting") {
			t.Fatalf("a malformed source_addr must be rejected at config LOAD, before the daemon starts (the startup log should never appear); output:\n%s", out)
		}
		if !strings.Contains(out, "invalid source_addr") {
			t.Fatalf("expected config.normalize's invalid-source_addr error; output:\n%s", out)
		}
		t.Logf("malformed-source_addr: wanbond exited %d at config load as expected:\n%s", code, out)
	})
}

// writeT60EdgeConfig writes a minimal, otherwise-valid edge config (role, psk,
// wireguard private/peer key, a bogus-but-syntactically-fine peer endpoint) with
// pathsBlock spliced in as the [[paths]] section(s) — the ONLY thing under test in
// TestTolerantStartupFastFailModes. Neither subtest reaches the peer, so the
// endpoint/allowed_ips values need not be routable.
//
// [log] level is "info" (NOT "error"): the zero-bindable subtest distinguishes a
// fatal Open() from a config-load failure by asserting the "wanbond starting" marker
// (main.Info, cmd/wanbond/main.go) IS present — that marker is logged at Info, so an
// "error" level would suppress it and the assertion could never hold (the daemon runs
// but logs nothing at Info). The malformed-source_addr subtest still sees NO
// "wanbond starting" because config load fails BEFORE that log, independent of level.
func writeT60EdgeConfig(t *testing.T, pathsBlock string) string {
	t.Helper()
	edgePriv, _ := genKey(t)
	_, concPub := genKey(t)
	psk := randKey(t)
	dir := t.TempDir()
	return writeConfig(t, filepath.Join(dir, "edge.toml"), fmt.Sprintf(`role = "edge"
psk = "%s"

%s
[wireguard]
private_key = "%s"

[[wireguard.peers]]
public_key = "%s"
endpoint = "192.0.2.53:51820"
allowed_ips = ["10.10.0.2/32"]

[log]
level = "info"
`, psk, pathsBlock, edgePriv, concPub))
}

// runWanbondOnce runs bin --config cfgPath to completion — no signal is sent; the
// process must exit ON ITS OWN — within deadline, and returns its exit code and
// combined stdout+stderr. It fails the test if the process does not exit within the
// deadline: for these two fast-fail scenarios a hang would mean Open (or config
// load) blocked instead of failing fast, which is itself a defect worth surfacing
// loudly rather than silently killing the process and reporting a false pass.
func runWanbondOnce(t *testing.T, bin, cfgPath string, deadline time.Duration) (exitCode int, output string) {
	t.Helper()
	ctx, cancel := context.WithTimeout(context.Background(), deadline)
	defer cancel()
	cmd := exec.CommandContext(ctx, bin, "--config", cfgPath)
	out, err := cmd.CombinedOutput()
	if ctx.Err() == context.DeadlineExceeded {
		t.Fatalf("wanbond did not exit within %s (expected a fast fail); output so far:\n%s", deadline, out)
	}
	if err == nil {
		return 0, string(out)
	}
	var ee *exec.ExitError
	if errors.As(err, &ee) {
		return ee.ExitCode(), string(out)
	}
	t.Fatalf("run wanbond --config %s: %v\n%s", cfgPath, err, out)
	return -1, string(out)
}

// setupT60Tunnel is setupMultipathTunnelLevel plus an edge [metrics] listen block:
// T60 needs to scrape the edge's per-path wanbond_path_up series to observe the
// deferred path being absent, then promoted. It otherwise mirrors
// setupMultipathTunnelLevel's config shape and bring-up sequence exactly.
func setupT60Tunnel(t *testing.T, top *Topology, bin string, paths []pathSpec, metricsListen string) (edge, conc *proc) {
	t.Helper()

	edgePriv, edgePub := genKey(t)
	concPriv, concPub := genKey(t)
	psk := randKey(t)

	var edgePaths, concPaths strings.Builder
	for _, p := range paths {
		fmt.Fprintf(&edgePaths, "[[paths]]\nname = %q\nsource_addr = %q\ndest_addr = \"%s:%d\"\n\n", p.name, p.edgeIP, p.concIP, listenPort)
		fmt.Fprintf(&concPaths, "[[paths]]\nname = %q\nsource_addr = %q\n\n", p.name, p.concIP)
	}
	// The wireguard peer endpoint (edge -> concentrator) seeds the virtual endpoint;
	// the first configured path's concentrator address serves (mirrors
	// setupMultipathTunnelLevel).
	primary := paths[0]
	metricsBlock := fmt.Sprintf("[metrics]\nlisten = %q\n\n", metricsListen)

	dir := t.TempDir()
	edgeCfg := writeConfig(t, filepath.Join(dir, "edge.toml"), fmt.Sprintf(`role = "edge"
psk = "%s"

%s%s[wireguard]
private_key = "%s"

[[wireguard.peers]]
public_key = "%s"
endpoint = "%s:%d"
allowed_ips = ["%s/32"]

[log]
level = "error"
`, psk, edgePaths.String(), metricsBlock, edgePriv, concPub, primary.concIP, listenPort, concInner))

	concCfg := writeConfig(t, filepath.Join(dir, "conc.toml"), fmt.Sprintf(`role = "concentrator"
psk = "%s"

%s[wireguard]
private_key = "%s"
listen_port = %d

[[wireguard.peers]]
public_key = "%s"
allowed_ips = ["%s/32"]

[log]
level = "error"
`, psk, concPaths.String(), concPriv, listenPort, edgePub, edgeInner))

	conc = top.startProc(t, "concentrator", "nsenter", "-t", strconv.Itoa(top.pid), "-n", bin, "--config", concCfg)
	edge = top.startProc(t, "edge", bin, "--config", edgeCfg)

	if !top.waitLink(tunDev, false, 5*time.Second) {
		t.Fatalf("edge %s never appeared\n%s", tunDev, edge.log())
	}
	if !top.waitLink(tunDev, true, 5*time.Second) {
		t.Fatalf("concentrator %s never appeared\n%s", tunDev, conc.log())
	}
	top.run("ip", "addr", "add", edgeInner+"/24", "dev", tunDev)
	top.run("ip", "link", "set", tunDev, "up")
	top.nsenter("ip", "addr", "add", concInner+"/24", "dev", tunDev)
	top.nsenter("ip", "link", "set", tunDev, "up")
	return edge, conc
}

// scrapeMetrics is a one-shot scrape of url, failing the test on any error (used
// once the endpoint is already known to be up — unlike waitPathUp's tolerant poll).
func scrapeMetrics(t *testing.T, url string) metrics.Exposition {
	t.Helper()
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	exp, err := metrics.Fetch(ctx, http.DefaultClient, url)
	if err != nil {
		t.Fatalf("scrape %s: %v", url, err)
	}
	return exp
}

// waitPathUp polls url's /metrics until the named path's wanbond_path_up series
// reads want, or fails the test at deadline. A scrape error is tolerated mid-poll
// (transient — never the terminal condition), since the assertion is about the
// SERIES VALUE appearing, not about the endpoint's own availability (already proven
// up by an earlier successful scrape in the caller).
func waitPathUp(t *testing.T, url, path string, want float64, deadline time.Duration) {
	t.Helper()
	end := time.Now().Add(deadline)
	var lastErr error
	for time.Now().Before(end) {
		ctx, cancel := context.WithTimeout(context.Background(), 1*time.Second)
		exp, err := metrics.Fetch(ctx, http.DefaultClient, url)
		cancel()
		if err != nil {
			lastErr = err
		} else if v, ok := exp.PathValue(metrics.MetricUp, path); ok && v == want {
			return
		}
		time.Sleep(100 * time.Millisecond)
	}
	t.Fatalf("wanbond_path_up{path=%q} never reached %v within %s (last scrape error: %v)", path, want, deadline, lastErr)
}

package device

import (
	"context"
	"net/netip"
	"sync"
	"time"

	"github.com/7mind/wanbond/internal/config"
	"github.com/7mind/wanbond/internal/dnsresolve"
	"github.com/7mind/wanbond/internal/log"
	"github.com/7mind/wanbond/internal/telemetry"
)

// nameTarget is one hostname endpoint spec the re-resolution controller tracks: the index of
// its owning failoverSpec (which equals the entry's position in config.Peer.EndpointSpecs, since
// the failover specs are built 1:1 in TOML order) together with the host/port to resolve. Only
// hostname specs (EndpointSpec.IsName) become nameTargets; literal specs never re-resolve.
type nameTarget struct {
	specIdx int
	host    string
	port    uint16
}

// resolution is the edge-side re-resolution controller (Q31/T73). It re-resolves each opted-in
// hostname peer-endpoint spec on a fixed poll cadence AND out-of-band the instant every path to
// the ACTIVE concentrator goes DOWN, then hands the fresh record set to hubFailover's update API
// so the bond is repointed only on an ACTUAL change (D32 suppression lives inside updateResolution).
//
// It mirrors the hubFailover shape: a pure constructor over injected collaborators (a
// dnsresolve.Resolver, the hubFailover whose update API / active-spec identity / shared liveness
// plane it drives, a telemetry.Clock, and the [dns] poll interval + per-lookup timeout), so its
// decision logic is unit-testable against a fake resolver, a fake clock, and a hubFailover built
// over fake health/remote. Resolution runs entirely OFF the send hot path — its own goroutine
// performs the network lookups; results are applied only through updateResolution under the
// endpoint-set lock (Q34: the two controllers coordinate purely through that shared lock and the
// update API, never a second, competing repoint path).
//
// RETENTION INVARIANT (D46): a lookup that FAILS (error/timeout/NXDOMAIN) or yields an EMPTY
// address set NEVER publishes — the spec keeps its last-good expansion and the controller retries
// next tick. A working endpoint set is therefore never torn down by a transient resolver fault,
// and hubFailover never sees an empty active spec that its total<2 guard could strand the bond on.
type resolution struct {
	resolver dnsresolve.Resolver
	// fo is the hub-failover controller this resolver drives: the sole mutation point
	// (updateResolution), the active-spec identity, and the shared liveness plane all live there.
	fo *hubFailover
	// targets is the ordered set of hostname specs to re-resolve; empty for an all-literal peer,
	// in which case the loop is a no-op.
	targets []nameTarget
	// families is the set of IP families the local path sockets can source traffic from (a v4
	// source_addr path reaches only v4 endpoints, a v6 path only v6). A resolved address of a
	// family NO local path can source is unreachable and is dropped from a spec's expansion — else
	// an AAAA-only answer on v4-only paths would repoint the bond at an address no path can carry.
	families pathFamilies

	clock        telemetry.Clock
	pollInterval time.Duration
	timeout      time.Duration
	log          log.Logger

	mu sync.Mutex
	// nextPollAt is when the next SCHEDULED full poll of every hostname spec is due (clock time).
	// Initialized to construction time so the first step polls immediately (prompt boot adoption
	// for a hostname-only peer). Advanced by the TTL-clamped poll delay after each poll, and reset
	// after an out-of-band liveness-loss re-resolve so the two do not double-resolve back to back.
	// Guarded by mu.
	nextPollAt time.Time
	// lastAllDown is the previous liveness-loss reading, so the out-of-band re-resolve is
	// EDGE-triggered (fires once when hub loss is first observed, not every tick while it
	// persists — the poll loop covers a sustained outage without hammering the resolver).
	// Guarded by mu.
	lastAllDown bool
}

// newResolution builds the controller over its injected collaborators. It is a pure constructor
// (no goroutine, no engine dependency) so a test drives step/pollAll directly against a fake
// resolver and a fake clock. nextPollAt is armed at construction time so the first step polls
// immediately.
func newResolution(resolver dnsresolve.Resolver, fo *hubFailover, targets []nameTarget, families pathFamilies, clock telemetry.Clock, pollInterval, timeout time.Duration, lg log.Logger) *resolution {
	return &resolution{
		resolver:     resolver,
		fo:           fo,
		targets:      targets,
		families:     families,
		clock:        clock,
		pollInterval: pollInterval,
		timeout:      timeout,
		log:          lg,
		nextPollAt:   clock.Now(),
	}
}

// nameTargetsFromSpecs extracts the hostname specs (EndpointSpec.IsName) from an ordered spec
// list as nameTargets, tagging each with its index in that list — which equals its failoverSpec
// index, since both are built 1:1 in TOML order. Literal specs contribute nothing.
func nameTargetsFromSpecs(specs []config.EndpointSpec) []nameTarget {
	var ts []nameTarget
	for i, s := range specs {
		if s.IsName {
			ts = append(ts, nameTarget{specIdx: i, host: s.Host, port: s.Port})
		}
	}
	return ts
}

// pathFamilies records which IP families the local path sockets can source traffic from. A path
// binds a socket whose family is fixed by its source_addr (bind.listenOnDevice): a v4 source can
// only reach v4 endpoints, a v6 source only v6. Re-resolution filters a resolved record set to the
// families at least one local path can source, so a lookup answer of an unreachable family (an
// AAAA-only answer on a v4-only edge) never repoints the bond at an address no path can carry.
type pathFamilies struct {
	v4 bool
	v6 bool
}

// allows reports whether a resolved address's family can be sourced by at least one local path.
func (f pathFamilies) allows(a netip.Addr) bool {
	if a.Unmap().Is4() {
		return f.v4
	}
	return f.v6
}

// pathFamiliesFromPaths derives the usable-family set from the configured paths. Config validation
// guarantees every path carries a valid source_addr (Config.normalize), so each path contributes
// exactly one family and the result is non-empty for any peer that reaches this controller.
func pathFamiliesFromPaths(paths []config.Path) pathFamilies {
	var f pathFamilies
	for _, p := range paths {
		if p.SourceAddr.Unmap().Is4() {
			f.v4 = true
		} else {
			f.v6 = true
		}
	}
	return f
}

// step is one evaluation at the probe cadence: it first services a liveness-loss edge (an
// out-of-band re-resolve of the active spec the instant every path goes DOWN), then, if the
// scheduled poll is due, re-resolves every hostname spec and re-arms the next poll at the
// TTL-clamped cadence. It is cheap in the steady state (a liveness read plus a clock compare)
// and performs its network lookups off any lock, so a periodic loop may call it at probe cadence.
func (r *resolution) step() {
	r.checkLivenessLoss()

	r.mu.Lock()
	due := !r.clock.Now().Before(r.nextPollAt)
	r.mu.Unlock()
	if !due {
		return
	}
	delay := r.pollAll()
	r.mu.Lock()
	r.nextPollAt = r.clock.Now().Add(delay)
	r.mu.Unlock()
}

// pollAll re-resolves every tracked hostname spec once and returns the delay until the next
// scheduled poll: the configured poll interval, CLAMPED to the smallest positive TTL reported by
// any spec whose transport exposes one (DoH/DoT ttlOk) — the Q31 TTL nice-to-have — so a record
// about to expire is re-checked no later than its TTL. A lookup failure or empty result leaves
// that spec's expansion untouched (RETENTION INVARIANT) and does not shorten the delay.
func (r *resolution) pollAll() time.Duration {
	delay := r.pollInterval
	for _, t := range r.targets {
		if d := r.clampPollDelay(r.resolveTarget(t)); d < delay {
			delay = d
		}
	}
	return delay
}

// clampPollDelay returns the scheduled poll interval clamped DOWN to a positive, meaningful TTL,
// so a record about to expire is re-checked no later than its TTL (Q31 TTL clamp). A lookup that
// exposes no TTL (ttlOk=false — system resolver) or a non-positive one leaves the full interval.
// It is applied uniformly to the scheduled poll re-arm AND the out-of-band liveness-loss re-arm,
// so the clamp invariant holds on BOTH paths — including the hub-loss window where record
// freshness matters most.
func (r *resolution) clampPollDelay(minTTL time.Duration, ttlOk bool) time.Duration {
	if ttlOk && minTTL > 0 && minTTL < r.pollInterval {
		return minTTL
	}
	return r.pollInterval
}

// resolveTarget performs one context-bounded lookup for a single hostname spec and, on a
// non-empty SUCCESS, hands the family-filtered, ordered record set to hubFailover.updateResolution (which
// suppresses a no-op change and repoints only on an actual active-IP change). It returns the
// lookup's minimum TTL and whether that TTL is meaningful, for the caller's clamp.
//
// RETENTION INVARIANT (D46): on ANY failure (error/timeout/NXDOMAIN) OR an empty ordered set
// (NODATA / a CNAME-only chain / a family the local paths cannot use), it publishes NOTHING —
// the spec keeps its previous expansion — and reports (0, false). A previously-resolved hostname
// is therefore never collapsed to empty, which is exactly the condition that could strand the
// bond under hubFailover's total<2 guard.
func (r *resolution) resolveTarget(t nameTarget) (time.Duration, bool) {
	ctx, cancel := r.lookupContext()
	defer cancel()

	addrs, minTTL, ttlOk, err := r.resolver.Lookup(ctx, t.host)
	if err != nil {
		r.log.Debug("dns re-resolution: lookup failed; retaining last-good records",
			"host", t.host, "spec_index", t.specIdx, "error", err.Error())
		return 0, false
	}
	eps := orderAddrPorts(addrs, t.port, r.families)
	if len(eps) == 0 {
		r.log.Debug("dns re-resolution: no usable record for local path families; retaining last-good records",
			"host", t.host, "spec_index", t.specIdx)
		return 0, false
	}
	r.fo.updateResolution(t.specIdx, eps)
	return minTTL, ttlOk
}

// checkLivenessLoss fires the out-of-band re-resolve of the ACTIVE spec on the DOWN edge — the
// tick at which every path to the active concentrator first reads DOWN. It coordinates with
// hubFailover purely through the shared liveness read (allPathsDown) and active-spec identity
// (activeSpecIndex): a hub-loss advance and a liveness-loss re-resolve therefore derive from one
// detector. The trigger is edge-triggered so a sustained outage re-resolves once here (the poll
// loop covers the rest) rather than on every tick.
func (r *resolution) checkLivenessLoss() {
	down := r.fo.allPathsDown()

	r.mu.Lock()
	edge := down && !r.lastAllDown
	r.lastAllDown = down
	r.mu.Unlock()
	if !edge {
		return
	}

	active := r.fo.activeSpecIndex()
	t, ok := r.targetFor(active)
	if !ok {
		// The active spec is a literal (or there is no active entry yet): nothing to re-resolve.
		return
	}
	r.log.Warn("dns re-resolution: all paths to active concentrator down; out-of-band re-resolve",
		"host", t.host, "spec_index", t.specIdx)
	minTTL, ttlOk := r.resolveTarget(t)

	// An out-of-band re-resolve subsumes the scheduled poll for this instant; push the next poll
	// out — but re-arm at the TTL-CLAMPED delay, not a blind full interval, so a short-TTL record
	// is re-checked no later than its TTL on exactly the hub-loss path where freshness matters most.
	r.mu.Lock()
	r.nextPollAt = r.clock.Now().Add(r.clampPollDelay(minTTL, ttlOk))
	r.mu.Unlock()
}

// targetFor returns the nameTarget owning specIdx, or ok=false when no tracked hostname spec has
// that index (a literal active spec, or specIdx == -1 for no active entry).
func (r *resolution) targetFor(specIdx int) (nameTarget, bool) {
	if specIdx < 0 {
		return nameTarget{}, false
	}
	for _, t := range r.targets {
		if t.specIdx == specIdx {
			return t, true
		}
	}
	return nameTarget{}, false
}

// lookupContext returns a context bounded by the configured per-lookup timeout (a non-positive
// timeout yields an unbounded context — the caller's config validation keeps it positive).
func (r *resolution) lookupContext() (context.Context, context.CancelFunc) {
	if r.timeout <= 0 {
		return context.WithCancel(context.Background())
	}
	return context.WithTimeout(context.Background(), r.timeout)
}

// orderAddrPorts turns a resolver's mixed A/AAAA record set into the ordered, deduplicated
// []netip.AddrPort a failoverSpec expansion requires: IPv4 records first (in resolver order),
// then IPv6, each paired with the spec's port. The order is DETERMINISTIC so an unchanged DNS
// answer produces a byte-identical expansion tick after tick — the precondition for
// updateResolution's active-AddrPort survival check to suppress a no-op repoint. Invalid or
// duplicate addrs, and addrs of a family NO local path can source (fams), are dropped — so a
// record set that filters down to nothing yields an empty expansion the caller retains last-good on.
func orderAddrPorts(addrs []netip.Addr, port uint16, fams pathFamilies) []netip.AddrPort {
	seen := make(map[netip.Addr]struct{}, len(addrs))
	var v4, v6 []netip.AddrPort
	for _, a := range addrs {
		if !a.IsValid() || !fams.allows(a) {
			continue
		}
		canon := a.Unmap()
		if _, dup := seen[canon]; dup {
			continue
		}
		seen[canon] = struct{}{}
		ap := netip.AddrPortFrom(canon, port)
		if canon.Is4() {
			v4 = append(v4, ap)
		} else {
			v6 = append(v6, ap)
		}
	}
	return append(v4, v6...)
}

// startResolutionLoop launches the re-resolution goroutine: it calls step every interval until
// the returned stopper is invoked (idempotent). It mirrors startHubFailoverLoop — a wall-clock
// ticker at the probe cadence driving a decision method whose every timing choice runs through
// the injected Clock, so a test drives step directly against a fake clock and never starts this
// goroutine. It is a no-op (no-op stopper) for a controller with no hostname specs to track or a
// non-positive interval.
func (r *resolution) startResolutionLoop(interval time.Duration) (stop func()) {
	if len(r.targets) == 0 || interval <= 0 {
		return func() {}
	}
	done := make(chan struct{})
	go func() {
		ticker := time.NewTicker(interval)
		defer ticker.Stop()
		for {
			select {
			case <-done:
				return
			case <-ticker.C:
				r.step()
			}
		}
	}()
	var once sync.Once
	return func() { once.Do(func() { close(done) }) }
}

package dnsresolve

import (
	"context"
	"net/netip"
	"time"
)

// Resolver resolves a hostname to its full A+AAAA record set, context-bounded.
// Implementations return addrs deterministically (both v4 and v6 when present);
// the caller filters/orders by local path family (device.orderAddrPorts drops
// addrs of a family no local path can source and puts v4 ahead of v6).
//
// minTTL is the minimum TTL across the returned records when the transport
// exposes it; ttlOk reports whether minTTL is meaningful — it is false when the
// transport discards TTL information (e.g. Go's standard net.Resolver never
// exposes it).
type Resolver interface {
	Lookup(ctx context.Context, host string) (addrs []netip.Addr, minTTL time.Duration, ttlOk bool, err error)
}

