package dnsresolve

import (
	"fmt"
	"net/netip"
	"strings"
	"time"

	"golang.org/x/net/dns/dnsmessage"
)

// buildQuery packs a single-question A/AAAA query with a DNS ID of 0, shared
// by both the DoH (RFC 8484) and DoT (RFC 7858) transports. Per RFC 8484
// SS4.1 the zero ID maximizes HTTP cache friendliness for DoH; for DoT it is
// simply harmless, since DoT queries aren't cached by an intermediary.
func buildQuery(host string, qtype dnsmessage.Type) ([]byte, error) {
	name, err := dnsmessage.NewName(fqdn(host))
	if err != nil {
		return nil, err
	}
	msg := dnsmessage.Message{
		Header: dnsmessage.Header{
			ID:               0,
			RecursionDesired: true,
		},
		Questions: []dnsmessage.Question{
			{Name: name, Type: qtype, Class: dnsmessage.ClassINET},
		},
	}
	return msg.Pack()
}

// parseAnswer unpacks body as a DNS response to a qtype query for host, and
// extracts the qtype-matching addrs and their minimum TTL. endpoint
// identifies the resolver for error messages (a DoH URL or a DoT
// server:port) — shared by both transports.
func parseAnswer(endpoint string, body []byte, host string, qtype dnsmessage.Type) ([]netip.Addr, time.Duration, bool, error) {
	var msg dnsmessage.Message
	if err := msg.Unpack(body); err != nil {
		return nil, 0, false, &MalformedResponseError{Endpoint: endpoint, Err: err}
	}

	if msg.RCode == dnsmessage.RCodeNameError {
		return nil, 0, false, &NXDomainError{Endpoint: endpoint, Host: host}
	}
	if msg.RCode != dnsmessage.RCodeSuccess {
		return nil, 0, false, &MalformedResponseError{Endpoint: endpoint, Err: fmt.Errorf("response RCode %v", msg.RCode)}
	}

	var addrs []netip.Addr
	var minTTL time.Duration
	haveTTL := false
	for _, ans := range msg.Answers {
		if ans.Header.Class != dnsmessage.ClassINET {
			continue
		}

		var addr netip.Addr
		switch res := ans.Body.(type) {
		case *dnsmessage.AResource:
			if qtype != dnsmessage.TypeA {
				continue
			}
			addr = netip.AddrFrom4(res.A)
		case *dnsmessage.AAAAResource:
			if qtype != dnsmessage.TypeAAAA {
				continue
			}
			addr = netip.AddrFrom16(res.AAAA)
		default:
			continue
		}

		addrs = append(addrs, addr)
		ttl := time.Duration(ans.Header.TTL) * time.Second
		if !haveTTL || ttl < minTTL {
			minTTL = ttl
			haveTTL = true
		}
	}

	return addrs, minTTL, haveTTL, nil
}

// fqdn returns host with a trailing dot, as dnsmessage.Name requires.
func fqdn(host string) string {
	if strings.HasSuffix(host, ".") {
		return host
	}
	return host + "."
}

// MalformedResponseError reports a resolver response body that failed to
// decode as a valid DNS message, or that decoded to an unexpected RCode.
// Shared by the DoH and DoT transports.
type MalformedResponseError struct {
	Endpoint string
	Err      error
}

func (e *MalformedResponseError) Error() string {
	return fmt.Sprintf("dnsresolve: %s returned a malformed response: %v", e.Endpoint, e.Err)
}

func (e *MalformedResponseError) Unwrap() error { return e.Err }

// TimeoutError reports a resolver request that did not complete within its
// deadline. Shared by the DoH and DoT transports.
type TimeoutError struct {
	Endpoint string
	Err      error
}

func (e *TimeoutError) Error() string {
	return fmt.Sprintf("dnsresolve: %s request timed out: %v", e.Endpoint, e.Err)
}

func (e *TimeoutError) Unwrap() error { return e.Err }

// NXDomainError reports a resolver answering NXDOMAIN for one address
// family. Lookup tolerates this as long as the other family answers. Shared
// by the DoH and DoT transports.
type NXDomainError struct {
	Endpoint string
	Host     string
}

func (e *NXDomainError) Error() string {
	return fmt.Sprintf("dnsresolve: %s: no such host %q", e.Endpoint, e.Host)
}

// NoDataError reports a resolver answering NOERROR with an empty final
// A+AAAA addr set for host (NODATA, or a CNAME chain with no A/AAAA
// target). It is the DoH/DoT-transport counterpart of the no-such-host error
// net.Resolver.LookupNetIP returns in the same situation. Shared by the DoH
// and DoT transports.
type NoDataError struct {
	Endpoint string
	Host     string
}

func (e *NoDataError) Error() string {
	return fmt.Sprintf("dnsresolve: %s: no A/AAAA records for %q", e.Endpoint, e.Host)
}

package dnsresolve

import (
	"context"
	"net"
	"net/netip"
	"time"
)

// SystemResolver resolves hostnames via the Go standard resolver (net.Resolver),
// requesting both A and AAAA records in one call (net.LookupNetIP-shape). The
// standard resolver does not expose record TTLs, so Lookup always returns
// ttlOk=false.
type SystemResolver struct {
	resolver *net.Resolver
}

var _ Resolver = (*SystemResolver)(nil)

// NewSystemResolver returns a Resolver backed by net.DefaultResolver.
func NewSystemResolver() *SystemResolver {
	return &SystemResolver{resolver: net.DefaultResolver}
}

// Lookup implements Resolver.
func (s *SystemResolver) Lookup(ctx context.Context, host string) ([]netip.Addr, time.Duration, bool, error) {
	addrs, err := s.resolver.LookupNetIP(ctx, "ip", host)
	if err != nil {
		return nil, 0, false, err
	}
	return addrs, 0, false, nil
}

//go:build e2e

package e2e

import (
	"encoding/json"
	"os/exec"
	"strconv"
	"strings"
	"testing"
	"time"
)

// TestMultipathReRoamSurvivesEdgeIPChange is the T16 acceptance: while a bulk TCP
// transfer runs over the bond, the edge's public IP on ONE path changes (a NAT
// rebind / CGNAT churn, emulated by re-addressing that path's edge veth). That
// path must RECOVER — the concentrator's Bind re-learns the path's new return
// endpoint from the next authenticated probe (T37) — the TCP transfer must
// complete with NO reset (the single virtual endpoint, hence the WireGuard
// session, is preserved), and the OTHER path must be undisturbed.
//
// The path chosen for re-addressing is the PRIMARY: the active-backup scheduler
// runs all traffic over it, so re-roaming it is the strongest test — the flow can
// only survive if that path comes back on its new address (or fails over and then
// back). Recovery is then proven UNAMBIGUOUSLY by blackholing the OTHER path and
// confirming the tunnel still carries traffic: that is possible only if the
// re-roamed primary is itself forwarding again on its new source address.
//
// Requires CAP_NET_ADMIN + /dev/net/tun; the plain `go test` never compiles it
// (e2e build tag), and it is run under the privileged netns harness.
func TestMultipathReRoamSurvivesEdgeIPChange(t *testing.T) {
	bin := buildWanbond(t)
	top := Setup(t)
	edge, conc := setupMultipathTunnel(t, top, bin, DefaultPaths)

	if !top.pingUntil(concInner, 15*time.Second) {
		t.Fatalf("bond never came up\n--- edge ---\n%s\n--- conc ---\n%s", edge.log(), conc.log())
	}

	primary := DefaultPaths[0] // starlink — the active-backup primary
	secondary := DefaultPaths[1]

	// A bulk TCP transfer that spans the re-roam. If the WG session resets, this
	// single connection breaks and iperf3 reports an error / zero sent bytes.
	xfer := top.startTransfer(t, concInner, 14)

	// Let the flow establish and ramp, then re-roam the primary path: the edge's
	// public IP on that path changes to a new host in the same /24. The edge's
	// device-bound path socket keeps sending, now sourced from the new address; the
	// concentrator re-learns it from the next authenticated probe.
	time.Sleep(2 * time.Second)
	newEdgeIP := reHost(primary.edgeIP, 111)
	t.Logf("re-roaming primary path %q: edge %s -> %s (mid-transfer)", primary.name, primary.edgeIP, newEdgeIP)
	top.Readdress(primary.name, newEdgeIP)

	// The tunnel must recover within the failover/recovery budget — the flow is
	// carried again end to end.
	if !top.pingUntil(concInner, time.Duration(P1RecoverySeconds)*time.Second+2*time.Second) {
		t.Fatalf("tunnel did not recover after re-roaming primary path %q to %s\n--- edge ---\n%s\n--- conc ---\n%s",
			primary.name, newEdgeIP, edge.log(), conc.log())
	}

	// The OTHER path is undisturbed by the re-roam (still reachable at L3).
	if !top.Reachable(secondary.name, 3) {
		t.Fatalf("secondary path %q became unreachable after re-roaming the primary", secondary.name)
	}

	// Prove the RE-ROAMED path itself recovered (not merely that the flow survived on
	// the backup): blackhole the secondary, so only the re-roamed primary can carry
	// traffic. The tunnel staying up means the primary is forwarding on its NEW
	// address — the concentrator re-learned the roamed endpoint.
	top.Blackhole(secondary.name)
	if !top.pingUntil(concInner, time.Duration(P1RecoverySeconds)*time.Second+2*time.Second) {
		t.Fatalf("re-roamed primary path %q did not recover: tunnel down once the backup %q was blackholed\n--- edge ---\n%s\n--- conc ---\n%s",
			primary.name, secondary.name, edge.log(), conc.log())
	}
	top.Restore(secondary.name)

	// The transfer must have completed across the whole window with NO reset: a
	// preserved single virtual endpoint keeps one WireGuard session, so the one TCP
	// connection survives the source-address change.
	mbps := xfer.result(t)
	if mbps <= 0 {
		t.Fatalf("TCP transfer across the re-roam measured non-positive throughput %.2f Mbit/s — the flow was reset", mbps)
	}

	// Both edge veths still exist: the re-roam re-addressed one link, it did not tear
	// the topology down.
	if !top.LinkExists(primary.name) || !top.LinkExists(secondary.name) {
		t.Fatalf("edge veth missing after re-roam: primary exists=%v secondary exists=%v",
			top.LinkExists(primary.name), top.LinkExists(secondary.name))
	}
	t.Logf("re-roam survived: primary %q recovered on %s, transfer completed at %.1f Mbit/s with no reset",
		primary.name, newEdgeIP, mbps)
}

// transfer is a background iperf3 TCP client whose completion (and reported
// throughput) is awaited via result(). It carries a single TCP connection so a WG
// session reset during the run surfaces as an error or zero sent bytes.
type transfer struct {
	cmd *exec.Cmd
	out *lockedBuffer
}

// startTransfer starts an iperf3 server in the concentrator netns and a client on
// the edge that transfers for secs seconds, returning immediately. The transfer
// spans a mid-run re-roam; result() awaits it and returns the sender throughput.
func (top *Topology) startTransfer(t *testing.T, serverIP string, secs int) *transfer {
	t.Helper()
	top.startProc(t, "iperf3-server", "nsenter", "-t", strconv.Itoa(top.pid), "-n", "iperf3", "-s", "-1", "-B", serverIP)
	time.Sleep(500 * time.Millisecond) // allow the server to bind and listen

	cmd := exec.Command("iperf3", "-c", serverIP, "-t", strconv.Itoa(secs), "-J")
	out := &lockedBuffer{}
	cmd.Stdout, cmd.Stderr = out, out
	if err := cmd.Start(); err != nil {
		t.Fatalf("start iperf3 client: %v", err)
	}
	return &transfer{cmd: cmd, out: out}
}

// result waits for the transfer to finish and returns the sender throughput in
// Mbit/s. A non-nil exit error (a reset connection) fails the test.
func (x *transfer) result(t *testing.T) float64 {
	t.Helper()
	if err := x.cmd.Wait(); err != nil {
		t.Fatalf("iperf3 transfer failed (connection reset during re-roam?): %v\n%s", err, x.out.String())
	}
	var r struct {
		End struct {
			SumSent struct {
				BitsPerSecond float64 `json:"bits_per_second"`
			} `json:"sum_sent"`
		} `json:"end"`
	}
	if err := json.Unmarshal([]byte(x.out.String()), &r); err != nil {
		t.Fatalf("parse iperf3 json: %v\n%s", err, x.out.String())
	}
	return r.End.SumSent.BitsPerSecond / 1e6
}

// reHost replaces the last octet of a dotted-quad IPv4 address with host, used to
// pick a fresh edge address in the same /24 for the re-roam.
func reHost(ip string, host int) string {
	i := strings.LastIndex(ip, ".")
	if i < 0 {
		return ip
	}
	return ip[:i+1] + strconv.Itoa(host)
}

package config

import (
	"errors"
	"fmt"
	"net"
	"net/netip"
	"net/url"
	"strings"
	"time"

	"github.com/7mind/wanbond/internal/dnsresolve"
)

// DNSResolverMode selects the transport dns.resolver picks.
type DNSResolverMode string

const (
	// DNSResolverSystem uses the OS stub resolver (dnsresolve.SystemResolver).
	// It is the default when [dns] is omitted or resolver is left empty.
	DNSResolverSystem DNSResolverMode = "system"
	// DNSResolverDoH uses DNS-over-HTTPS (dnsresolve.DoHResolver).
	DNSResolverDoH DNSResolverMode = "doh"
	// DNSResolverDoT uses DNS-over-TLS (dnsresolve.DoTResolver).
	DNSResolverDoT DNSResolverMode = "dot"
)

func (m DNSResolverMode) valid() bool {
	return m == DNSResolverSystem || m == DNSResolverDoH || m == DNSResolverDoT
}

// Default cadence/timeout for the [dns] block (Q31): the poll interval sits on
// the reconcile-cadence scale — frequent enough that a DDNS repoint is picked
// up promptly, far coarser than the sub-second deferred-path/probe loops
// (bind.DefaultReconcileInterval = 1s) since re-resolution costs a real
// network round trip to the configured resolver and re-resolving too eagerly
// would needlessly load it. The per-lookup timeout mirrors dnsresolve's own
// internal DoH/DoT bounds (5s).
const (
	defaultDNSPollInterval = 30 * time.Second
	defaultDNSTimeout      = 5 * time.Second
)

// dotDefaultPort mirrors dnsresolve's unexported dotPort: DNS-over-TLS's
// IANA-assigned port (RFC 7858 §3), and the ONLY port dnsresolve.NewDoTResolver
// ever dials (it appends this fixed port itself). An explicit port in
// dot_server must match it, so a mistyped non-standard port fails fast at
// config load rather than being silently ignored when the resolver is built.
const dotDefaultPort = "853"

// DNS selects and tunes the resolver transport used for opted-in hostname
// peer-endpoint re-resolution (Q29/Q31). An ABSENT [dns] block is INERT: it
// defaults to the system resolver, and resolution only happens at all when a
// peer separately opts in with its own `dns = true` flag (Peer.DNS) —
// [dns] merely selects which transport that opt-in uses, it is never a gate
// by itself.
type DNS struct {
	// Resolver selects the transport: "system" (default), "doh", or "dot".
	Resolver DNSResolverMode `toml:"resolver"`
	// DoHURL is the DNS-over-HTTPS query endpoint (an https:// URL). Required
	// iff resolver = "doh"; rejected (must stay empty) under any other
	// resolver.
	DoHURL string `toml:"doh_url"`
	// DoTServer is the DNS-over-TLS server: a bare host, or "host:port" where
	// port must be dotDefaultPort (853) — dnsresolve.NewDoTResolver always
	// dials that port itself, so any other explicit port cannot be honored.
	// Required iff resolver = "dot"; rejected (must stay empty) under any
	// other resolver.
	DoTServer string `toml:"dot_server"`
	// BootstrapIP is the literal IP address wanbond dials the DoH/DoT server
	// on when doh_url/dot_server names it by HOSTNAME rather than IP literal
	// (the chicken-and-egg BOOTSTRAP-IP invariant, Q33): resolving the
	// private resolver's own name would itself require a DNS lookup — via
	// the system resolver [dns] exists to avoid — defeating the point of
	// configuring a private resolver. Required iff the doh_url/dot_server
	// host is a hostname; rejected (must stay empty) when the host is
	// already an IP literal — there is nothing to bootstrap in that case, so
	// a non-empty value there is a mode mismatch, rejected fail-fast like the
	// other stray-field checks in validate.
	BootstrapIP string `toml:"bootstrap_ip"`
	// PollInterval is the re-resolution cadence for an opted-in hostname peer
	// endpoint (Q31), parsed from PollIntervalRaw in applyDefaults. Defaults to
	// defaultDNSPollInterval when PollIntervalRaw is left empty; must be > 0
	// after defaulting.
	PollInterval time.Duration `toml:"-"`
	// PollIntervalRaw is the TOML Go-duration string form of PollInterval,
	// e.g. "30s". Mirrors Path.LinkRTTRaw: go-toml/v2 cannot decode a TOML
	// string directly into a time.Duration field, so the raw string is parsed
	// via time.ParseDuration in applyDefaults.
	PollIntervalRaw string `toml:"poll_interval"`
	// Timeout bounds a single resolver lookup, parsed from TimeoutRaw in
	// applyDefaults. Defaults to defaultDNSTimeout when TimeoutRaw is left
	// empty; must be > 0 after defaulting.
	Timeout time.Duration `toml:"-"`
	// TimeoutRaw is the TOML Go-duration string form of Timeout, e.g. "5s".
	TimeoutRaw string `toml:"timeout"`
}

// applyDefaults fills the resolver mode and cadence/timeout knobs left at
// their zero value, so a minimal or absent [dns] block resolves to explicit,
// usable settings — an absent block still ends up as the system resolver
// with the standard cadence/timeout, per the type's zero-value contract.
// PollIntervalRaw/TimeoutRaw are parsed here (mirroring Path's *Raw-field
// normalize step for LinkRTTRaw); an unparseable duration string is reported
// immediately.
func (d *DNS) applyDefaults() error {
	if d.Resolver == "" {
		d.Resolver = DNSResolverSystem
	}
	if d.PollIntervalRaw == "" {
		d.PollInterval = defaultDNSPollInterval
	} else {
		v, err := time.ParseDuration(d.PollIntervalRaw)
		if err != nil {
			return fmt.Errorf("dns.poll_interval: invalid duration %q: %w", d.PollIntervalRaw, err)
		}
		d.PollInterval = v
	}
	if d.TimeoutRaw == "" {
		d.Timeout = defaultDNSTimeout
	} else {
		v, err := time.ParseDuration(d.TimeoutRaw)
		if err != nil {
			return fmt.Errorf("dns.timeout: invalid duration %q: %w", d.TimeoutRaw, err)
		}
		d.Timeout = v
	}
	return nil
}

// validate enforces the [dns] block invariants: a resolver-mode-appropriate
// set of required fields, no stray fields left over from a different mode,
// positive cadence/timeout, and the BOOTSTRAP-IP invariant for a hostname-form
// doh_url/dot_server. Runs after applyDefaults (mirroring Amnezia/FEC/
// SchedulerConfig), so Resolver/PollInterval/Timeout are already defaulted.
func (d DNS) validate() error {
	if !d.Resolver.valid() {
		return fmt.Errorf("dns.resolver must be %q, %q or %q, got %q", DNSResolverSystem, DNSResolverDoH, DNSResolverDoT, d.Resolver)
	}
	if d.PollInterval <= 0 {
		return fmt.Errorf("dns.poll_interval must be > 0, got %s", d.PollInterval)
	}
	if d.Timeout <= 0 {
		return fmt.Errorf("dns.timeout must be > 0, got %s", d.Timeout)
	}

	switch d.Resolver {
	case DNSResolverSystem:
		if d.DoHURL != "" {
			return errors.New("dns.doh_url is only meaningful when dns.resolver = \"doh\"")
		}
		if d.DoTServer != "" {
			return errors.New("dns.dot_server is only meaningful when dns.resolver = \"dot\"")
		}
		if d.BootstrapIP != "" {
			return errors.New("dns.bootstrap_ip is only meaningful when dns.resolver is \"doh\" or \"dot\"")
		}
		return nil
	case DNSResolverDoH:
		if d.DoTServer != "" {
			return errors.New("dns.dot_server is not meaningful when dns.resolver = \"doh\"")
		}
		if d.DoHURL == "" {
			return errors.New("dns.doh_url is required when dns.resolver = \"doh\"")
		}
		host, err := dohURLHost(d.DoHURL)
		if err != nil {
			return fmt.Errorf("dns.doh_url: %w", err)
		}
		return d.requireBootstrapForHost(host)
	case DNSResolverDoT:
		if d.DoHURL != "" {
			return errors.New("dns.doh_url is not meaningful when dns.resolver = \"dot\"")
		}
		if d.DoTServer == "" {
			return errors.New("dns.dot_server is required when dns.resolver = \"dot\"")
		}
		host, err := dotServerHost(d.DoTServer)
		if err != nil {
			return fmt.Errorf("dns.dot_server: %w", err)
		}
		return d.requireBootstrapForHost(host)
	default:
		// Unreachable: d.Resolver.valid() above already rejected anything else.
		return fmt.Errorf("dns.resolver: unhandled mode %q", d.Resolver)
	}
}

// requireBootstrapForHost enforces the BOOTSTRAP-IP invariant for the given
// (already-extracted) doh_url/dot_server host: an IP-literal host needs no
// bootstrap and rejects a stray bootstrap_ip as a mode mismatch (mirroring
// the doh_url/dot_server stray-field checks in validate — NewResolver would
// otherwise silently pin the dial to bootstrap_ip instead of the configured
// host); a hostname requires an explicit, valid bootstrap_ip.
func (d DNS) requireBootstrapForHost(host string) error {
	if _, err := netip.ParseAddr(host); err == nil {
		if d.BootstrapIP != "" {
			return fmt.Errorf("dns.bootstrap_ip is not meaningful when the doh_url/dot_server host %q is already an IP literal", host)
		}
		return nil
	}
	if d.BootstrapIP == "" {
		return fmt.Errorf("hostname %q requires dns.bootstrap_ip: the resolver's own address must be reachable without a DNS lookup (a plaintext lookup of the private resolver's own name would defeat the point of configuring one)", host)
	}
	if _, err := netip.ParseAddr(d.BootstrapIP); err != nil {
		return fmt.Errorf("dns.bootstrap_ip %q is not a valid IP literal: %w", d.BootstrapIP, err)
	}
	return nil
}

// dohURLHost extracts and validates the host component of a doh_url: it must
// be a well-formed https:// URL with a non-empty host.
func dohURLHost(rawURL string) (string, error) {
	u, err := url.Parse(rawURL)
	if err != nil {
		return "", fmt.Errorf("invalid URL %q: %w", rawURL, err)
	}
	if u.Scheme != "https" {
		return "", fmt.Errorf("must use https, got scheme %q in %q", u.Scheme, rawURL)
	}
	host := u.Hostname()
	if host == "" {
		return "", fmt.Errorf("missing host in %q", rawURL)
	}
	return host, nil
}

// dotServerHost extracts and validates the host component of a dot_server: a
// bare host (hostname or IP literal, no port) is accepted as-is; a
// "host:port" form is split and requires port == dotDefaultPort, since
// dnsresolve.NewDoTResolver always dials that fixed port itself.
func dotServerHost(raw string) (string, error) {
	if raw == "" {
		return "", errors.New("empty")
	}
	// A bare IP literal (including an unbracketed IPv6 literal, which itself
	// contains colons) has no port to split off.
	if _, err := netip.ParseAddr(raw); err == nil {
		return raw, nil
	}
	if !strings.Contains(raw, ":") {
		return raw, nil // bare hostname, no port
	}
	host, port, err := net.SplitHostPort(raw)
	if err != nil {
		return "", fmt.Errorf("invalid dot_server %q: %w", raw, err)
	}
	if port != dotDefaultPort {
		return "", fmt.Errorf("port %q must be %q (the IANA-assigned DNS-over-TLS port; dnsresolve always dials it)", port, dotDefaultPort)
	}
	return host, nil
}

// NewResolver constructs the dnsresolve.Resolver implementation the
// (validated) [dns] block selects: dnsresolve.NewSystemResolver for the
// default/system mode, dnsresolve.NewDoHResolver/NewDoTResolver for doh/dot,
// or their *WithBootstrap variants when bootstrap_ip is set. Callers
// normally obtain a DNS value via config.Load, which already ran
// applyDefaults/validate; calling this on an un-validated DNS value surfaces
// whatever the underlying dnsresolve constructor rejects.
//
// bootstrap_ip (validated fail-fast, see requireBootstrapForHost) IS wired
// into the constructed resolver's dial target: when set, the resolver dials
// bootstrap_ip directly instead of resolving the configured hostname through
// the system dialer — the BOOTSTRAP-IP invariant (Q33) exists precisely to
// avoid that plaintext lookup of the private resolver's own name.
func (d DNS) NewResolver() (dnsresolve.Resolver, error) {
	switch d.Resolver {
	case DNSResolverDoH:
		if d.BootstrapIP != "" {
			return dnsresolve.NewDoHResolverWithBootstrap(d.DoHURL, d.BootstrapIP)
		}
		return dnsresolve.NewDoHResolver(d.DoHURL)
	case DNSResolverDoT:
		host, err := dotServerHost(d.DoTServer)
		if err != nil {
			return nil, fmt.Errorf("dns.dot_server: %w", err)
		}
		if d.BootstrapIP != "" {
			return dnsresolve.NewDoTResolverWithBootstrap(host, d.BootstrapIP)
		}
		return dnsresolve.NewDoTResolver(host)
	default:
		return dnsresolve.NewSystemResolver(), nil
	}
}

// edge binds one source-addr'd socket per path and targets each path's
// concentrator address via dest_addr; the concentrator binds one socket per path
// on its own address. It addresses both TUNs and returns the running processes.
func setupMultipathTunnel(t *testing.T, top *Topology, bin string, paths []pathSpec) (edge, conc *proc) {
	t.Helper()
	return setupMultipathTunnelLevel(t, top, bin, paths, "error")
}

// setupMultipathTunnelLevel is setupMultipathTunnel with an explicit daemon log
// level. The P1 failover measurement (TestP1Failover) runs both daemons at "info"
// so the scheduler's per-direction "active path change" transitions are captured in
// each process's log for the root-cause evidence; every other caller uses "error".
func setupMultipathTunnelLevel(t *testing.T, top *Topology, bin string, paths []pathSpec, level string) (edge, conc *proc) {
	t.Helper()

	edgePriv, edgePub := genKey(t)
	concPriv, concPub := genKey(t)
	psk := randKey(t)

	var edgePaths, concPaths strings.Builder
	for _, p := range paths {
		fmt.Fprintf(&edgePaths, "[[paths]]\nname = %q\nsource_addr = %q\ndest_addr = \"%s:%d\"\n\n", p.name, p.edgeIP, p.concIP, listenPort)
		fmt.Fprintf(&concPaths, "[[paths]]\nname = %q\nsource_addr = %q\n\n", p.name, p.concIP)
	}
	// The wireguard peer endpoint (edge -> concentrator) seeds the virtual
	// endpoint; the primary path's concentrator address serves.
	primary := paths[0]

	dir := t.TempDir()
	edgeCfg := writeConfig(t, filepath.Join(dir, "edge.toml"), fmt.Sprintf(`role = "edge"
psk = "%s"

%s[wireguard]
private_key = "%s"

[[wireguard.peers]]
public_key = "%s"
endpoint = "%s:%d"
allowed_ips = ["%s/32"]

[log]
level = %q
`, psk, edgePaths.String(), edgePriv, concPub, primary.concIP, listenPort, concInner, level))

	concCfg := writeConfig(t, filepath.Join(dir, "conc.toml"), fmt.Sprintf(`role = "concentrator"
psk = "%s"

%s[wireguard]
private_key = "%s"
listen_port = %d

[[wireguard.peers]]
public_key = "%s"
allowed_ips = ["%s/32"]

[log]
level = %q
`, psk, concPaths.String(), concPriv, listenPort, edgePub, edgeInner, level))

	conc = top.startProc(t, "concentrator", "nsenter", "-t", strconv.Itoa(top.pid), "-n", bin, "--config", concCfg)
	edge = top.startProc(t, "edge", bin, "--config", edgeCfg)

	if !top.waitLink(tunDev, false, 5*time.Second) {
		t.Fatalf("edge %s never appeared\n%s", tunDev, edge.log())
	}
	if !top.waitLink(tunDev, true, 5*time.Second) {
		t.Fatalf("concentrator %s never appeared\n%s", tunDev, conc.log())
	}
	top.run("ip", "addr", "add", edgeInner+"/24", "dev", tunDev)
	top.run("ip", "link", "set", tunDev, "up")
	top.nsenter("ip", "addr", "add", concInner+"/24", "dev", tunDev)
	top.nsenter("ip", "link", "set", tunDev, "up")
	return edge, conc
}

// linkMTU returns the MTU of dev (in the peer netns when ns is true).
func (top *Topology) linkMTU(t *testing.T, dev string, ns bool) int {
	t.Helper()
	var out string
	if ns {
		out = top.runOut("nsenter", "-t", strconv.Itoa(top.pid), "-n", "ip", "-o", "link", "show", dev)
	} else {
		out = top.runOut("ip", "-o", "link", "show", dev)
	}
	// ... mtu 1401 ...
	fields := strings.Fields(out)
	for i, f := range fields {
		if f == "mtu" && i+1 < len(fields) {
			mtu, err := strconv.Atoi(fields[i+1])
			if err != nil {
				t.Fatalf("parse mtu %q: %v", fields[i+1], err)
			}
			return mtu
		}
	}
	t.Fatalf("no mtu field in %q", out)
	return 0
}

