792	// resolveBootEndpoints performs the bounded initial hostname resolve (Q30) and derives, per peer,
793	// the seeded failoverSpecs and the boot endpoint the UAPI render installs. It constructs the
794	// resolver AT MOST ONCE, and ONLY when some peer carries a hostname endpoint spec — a config with
795	// zero hostname specs never invokes newResolver, so its wiring is provably inert (Q29). A literal
796	// spec is seeded verbatim (byte-for-byte the pre-G5 behaviour); a hostname spec is resolved under
797	// the [dns] per-lookup timeout and family-filtered. A lookup that fails, times out, or yields no
798	// usable record leaves that spec EMPTY — the peer boots endpoint-less and the re-resolution loop
799	// installs it on first success (R70). A resolver that fails to construct is logged and treated as
800	// absent (every hostname spec then boots empty), since re-resolution must never fail bring-up.
801	func resolveBootEndpoints(cfg *config.Config, newResolver resolverFactory, lg log.Logger) bootEndpoints {
802		peers := cfg.WireGuard.Peers
803		b := bootEndpoints{
804			specs:     make([][]failoverSpec, len(peers)),
805			endpoints: make([]bootEndpoint, len(peers)),
806		}
807	
808		hasName := false
809		for _, p := range peers {
810			for _, s := range p.EndpointSpecs {
811				if s.IsName {
812					hasName = true
813				}
814			}
815		}
816		if hasName {
817			if r, err := newResolver(); err != nil {
818				lg.Warn("dns: could not construct resolver; hostname endpoints boot endpoint-less and will not re-resolve",
819					"error", err.Error())
820			} else {
821				b.resolver = r
822			}
823		}
824	
825		fams := pathFamiliesFromPaths(cfg.Paths)
826		for i, p := range peers {
827			specs := make([]failoverSpec, len(p.EndpointSpecs))
828			for j, s := range p.EndpointSpecs {
829				if !s.IsName {
830					specs[j] = failoverSpec{spec: s, addrs: []netip.AddrPort{s.Addr}}
831					continue
832				}
833				var addrs []netip.AddrPort
834				if b.resolver != nil {
835					addrs = bootResolveHostname(b.resolver, s, fams, cfg.DNS.Timeout, lg)
836				}
837				specs[j] = failoverSpec{spec: s, addrs: addrs}
838			}
839			b.specs[i] = specs
840			// The boot endpoint is the FLATTENED head — the first spec (in TOML order) with a
841			// non-empty expansion. None ⇒ endpoint-less boot.
842			for _, sp := range specs {
843				if len(sp.addrs) > 0 {
844					b.endpoints[i] = bootEndpoint{ap: sp.addrs[0], valid: true}
845					break
846				}
847			}
848		}
849		return b
850	}
