852	// bootResolveHostname does one context-bounded lookup for a hostname spec at boot and returns the
853	// ordered, family-filtered []netip.AddrPort (empty on any failure/timeout/empty-result — the caller
854	// then boots that spec endpoint-less). The timeout is the [dns] per-lookup timeout (kept > 0 by
855	// config validation); a non-positive value falls back to an unbounded context, matching
856	// resolution.lookupContext, but Up should never pass one.
857	func bootResolveHostname(resolver dnsresolve.Resolver, s config.EndpointSpec, fams pathFamilies, timeout time.Duration, lg log.Logger) []netip.AddrPort {
858		ctx := context.Background()
859		if timeout > 0 {
860			var cancel context.CancelFunc
861			ctx, cancel = context.WithTimeout(ctx, timeout)
862			defer cancel()
863		}
864		addrs, _, _, err := resolver.Lookup(ctx, s.Host)
865		if err != nil {
866			lg.Info("dns: initial resolve failed; endpoint boots deferred to the re-resolution loop",
867				"host", s.Host, "error", err.Error())
868			return nil
869		}
870		eps := orderAddrPorts(addrs, s.Port, fams)
871		if len(eps) == 0 {
872			lg.Info("dns: initial resolve yielded no usable record for local path families; endpoint boots deferred",
873				"host", s.Host)
874			return nil
875		}
876		return eps
877	}
